select id="wb-position-role" class="modal-select"><option value="system">Hệ thống (System)</option><option value="user">Người dùng (User)</option><option value="assistant">Trợ lý (Assistant)</option></select></div></div><div class="modal-form-grid"><div class="modal-form-group"><label>Chiến lược kích hoạt</label><button type="button" id="wb-strategy-toggle-btn" class="editor-btn" style="width:100%; margin-left:0;"></button></div><div class="modal-form-group" style="display: flex; flex-direction: column; justify-content: center; gap: 10px;"><div style="display: flex; align-items: center; gap: 10px;"><input type="checkbox" id="wb-recursion-incoming" style="width: 18px; height: 18px; cursor: pointer;"><label for="wb-recursion-incoming" style="margin-bottom: 0; cursor: pointer;">Không đệ quy đến</label></div><div style="display: flex; align-items: center; gap: 10px;"><input type="checkbox" id="wb-recursion-outgoing" style="width: 18px; height: 18px; cursor: pointer;"><label for="wb-recursion-outgoing" style="margin-bottom: 0; cursor: pointer;">Ngăn chặn đệ quy đi</label></div></div></div><div class="modal-form-group" style="display: flex; align-items: center; gap: 10px;"><input type="checkbox" id="wb-modal-enabled" style="width: 18px; height: 18px; cursor: pointer;"><label for="wb-modal-enabled" style="margin-bottom: 0; cursor: pointer;">Kích hoạt mục này</label></div><div class="modal-actions"><button type="button" id="wb-modal-cancel-btn" class="editor-btn">Hủy bỏ</button><button type="button" id="wb-modal-save-btn" class="editor-btn btn-primary">Lưu</button></div></form></div></div>
