    <script>
      // Tác phẩm Loại Não/Lữ Đồ Mộng Tinh, nghiêm cấm re-up, nghiêm cấm thương mại hóa, chia sẻ mã nguồn mở miễn phí
      (function () {
        // --- Cấu hình toàn cục ---
        const LOREBOOK_NAME = '1 Quy Khư';

        // --- Kiểm tra tính khả dụng của API ---
        /* global TavernHelper, eventEmit, getChatMessages, getCurrentMessageId */
        if (
          typeof TavernHelper === 'undefined' ||
          typeof TavernHelper.getWorldbook === 'undefined' || // Kiểm tra API mới có tồn tại không
          typeof eventEmit === 'undefined' ||
          typeof getChatMessages === 'undefined' ||
          typeof getCurrentMessageId === 'undefined'
        ) {
          console.error('Không tìm thấy TavernHelper API hoặc hệ thống sự kiện, hoặc phiên bản quá cũ.');
          document.addEventListener('DOMContentLoaded', () => {
            document.body.innerHTML =
              '<h1 style="color: red; text-align: center;">Lỗi: Môi trường SillyTavern API không tìm thấy hoặc không tương thích. Vui lòng đảm bảo plugin TavernHelper đã được cập nhật.</h1>';
          });
          return;
        }

        // --- Trình phân tích YAML (Stack-based để xử lý lồng nhau) ---
        const YAMLParser = {
          parse: function (text) {
            if (!text || typeof text !== 'string') return {};
            const lines = text.split('\n');
            const result = {};
            const stack = [{ indent: -1, obj: result, lastKey: null }];

            for (const line of lines) {
                const trimmed = line.trim();
                if (!trimmed || trimmed.startsWith('#')) continue;

                const indent = line.search(/\S/);

                while (stack.length > 1 && indent <= stack[stack.length - 1].indent) {
                    stack.pop();
                }
                const parent = stack[stack.length - 1].obj;
                let lastKeyInParent = stack[stack.length - 1].lastKey;

                if (trimmed.startsWith('- ')) {
                    const value = trimmed.substring(2).trim();
                    if (lastKeyInParent && Array.isArray(parent[lastKeyInParent])) {
                        parent[lastKeyInParent].push(this._parseValue(value));
                    }
                } else {
                    const colonIndex = trimmed.indexOf(':');
                    if (colonIndex > -1) {
                        const key = trimmed.substring(0, colonIndex).trim();
                        let value = trimmed.substring(colonIndex + 1).trim();

                        stack[stack.length - 1].lastKey = key;

                        if (value === '|' || value === '>') {
                            let multiline = '';
                            const blockStartIndex = lines.indexOf(line) + 1;
                            for (let i = blockStartIndex; i < lines.length; i++) {
                                const nextLine = lines[i];
                                const nextIndent = nextLine.search(/\S/);
                                if (nextLine.trim() === '' || nextIndent > indent) {
                                    multiline += nextLine.substring(indent + 2) + '\n';
                                } else {
                                    break;
                                }
                            }
                            parent[key] = multiline.trim();
                        } else if (value === '') {
                             const nextLine = lines[lines.indexOf(line) + 1] || '';
                             const nextTrimmed = nextLine.trim();
                             const nextIndent = nextLine.search(/\S/);
                             if (nextTrimmed.startsWith('- ') && nextIndent > indent) {
                                 const newArr = [];
                                 parent[key] = newArr;
                             } else if (nextIndent > indent) {
                                 const newObj = {};
                                 parent[key] = newObj;
                                 stack.push({ indent: indent, obj: newObj, lastKey: null });
                             } else {
                                 parent[key] = '';
                             }
                        } else {
                            parent[key] = this._parseValue(value);
                        }
                    }
                }
            }
            return result;
          },

          stringify: function (data, indent = '') {
            let yaml = '';
            for (const [key, value] of Object.entries(data)) {
              if (Array.isArray(value)) {
                yaml += `${indent}${key}:\n`;
                for (const item of value) {
                  yaml += `${indent}  - ${item}\n`;
                }
              } else if (typeof value === 'object' && value !== null) {
                yaml += `${indent}${key}:\n`;
                yaml += this.stringify(value, indent + '  ');
              } else if (typeof value === 'string' && value.includes('\n')) {
                yaml += `${indent}${key}: |\n`;
                const lines = value.split('\n');
                for (const line of lines) {
                  yaml += `${indent}  ${line}\n`;
                }
              } else {
                yaml += `${indent}${key}: ${value}\n`;
              }
            }
            return yaml;
          },

          _parseValue: function (val) {
            const numVal = Number(val);
            if (!isNaN(numVal) && val.trim() !== '') {
              return numVal;
            }
            if (val === 'true') return true;
            if (val === 'false') return false;
            return val;
          },
        };

        // --- Quản lý dữ liệu Sách Thế Giới (Đã Fix: Tự động nhận diện tên sách & Bộ lọc) ---
      const WorldBookManager = {
          LOREBOOK_NAME: '1 Quy Khư', // Giá trị mặc định, sẽ được cập nhật tự động

          // Hàm tìm giá trị "mờ" (fuzzy) trong đối tượng YAML
          // Cho phép tìm kiếm không phân biệt hoa thường, có/không có dấu gạch dưới, có/không có dấu cách
          findFuzzyValue(obj, keys) {
              if (!obj || typeof obj !== 'object') return undefined;

              // Tạo map các key đã chuẩn hóa từ object
              const normalizedKeys = Object.keys(obj).reduce((acc, key) => {
                  const normalized = key.toLowerCase().replace(/[\s_]/g, '');
                  acc[normalized] = key;
                  return acc;
              }, {});

              for (const key of keys) {
                  // 1. Thử tìm chính xác
                  if (obj[key] !== undefined) return obj[key];

                  // 2. Thử tìm key đã chuẩn hóa
                  const normalizedSearch = key.toLowerCase().replace(/[\s_]/g, '');
                  const actualKey = normalizedKeys[normalizedSearch];
                  if (actualKey && obj[actualKey] !== undefined) return obj[actualKey];
              }
              return undefined;
          },

          // Hàm tự động tìm tên World Book hiện tại đang liên kết
          async detectActiveLorebook() {
              try {
                  // Lấy danh sách tất cả World Books đang có
                  const books = await TavernHelper.getLorebooks();
                  if (!books || books.length === 0) return;

                  // Ưu tiên 0: Tìm chính xác "1 Quy Khư"
                  if (books.includes('1 Quy Khư')) {
                      this.LOREBOOK_NAME = '1 Quy Khư';
                      console.log(`[Quy Khư] Đã tự động liên kết với Sách Thế Giới (Chính xác): "${this.LOREBOOK_NAME}"`);
                      return;
                  }

                  // Ưu tiên 1: Tìm sách có tên chứa "Quy Khư" (không phân biệt hoa thường/dấu)
                  let target = books.find(b => 
                      b.toLowerCase().includes('Quy Khư') || 
                      b.toLowerCase().includes('Quy Khu') || 
                      b.toLowerCase().includes('quy khư') || 
                      b.toLowerCase().includes('quy khu') ||
                      b.toLowerCase().includes('QuyKhư') ||
                      b.toLowerCase().includes('Quykhu') ||
                      b.toLowerCase().includes('quykhư') ||
                      b.toLowerCase().includes('quykhu') ||
                      b.includes('Quy Khư')
                  );

                  if (target) {
                      this.LOREBOOK_NAME = target;
                      console.log(`[Quy Khư] Đã tự động liên kết với Sách Thế Giới: "${this.LOREBOOK_NAME}"`);
                  }
              } catch (e) {
                  console.warn('[Quy Khư] Không thể tự động phát hiện tên Sách Thế Giới.', e);
              }
          },

          normalizeType(rawType) {
              if (!rawType) return '';
              const type = rawType.trim().toLowerCase();

              if (['Thiên Phú', 'ThiênPhú', 'Thiên phú', 'Thiênphú', 'thiên Phú', 'thiênPhú', 'thiên phú', 'thiênphú', 'talent', '天赋'].includes(type)) return 'Thiên Phú';
              if (['Xuất Thân', 'XuấtThân', 'Xuất thân', 'Xuấtthân', 'xuất Thân', 'xuấtThân', 'xuất thân', 'xuấtthân', 'background', '出身'].includes(type)) return 'Xuất Thân';
              if (['Khởi Đầu Mẫu', 'KhởiĐầuMẫu', 'Khởi Đầu Mẫu', 'Khởiđầumẫu', 'Khởi Đầu Mẫu', 'khởiđầumẫu', 'preset', '预设', '预设开局'].includes(type)) return 'Khởi Đầu Mẫu';
              // FIX: Thêm từ khóa 'thế giới' vào danh sách nhận diện
              if (['Thế Giới', 'ThếGiới', 'Thế giới', 'Thếgiới', 'thế Giới', 'thếGiới', 'thế giới', 'thếgiới'].includes(type)) return 'Thế Giới';

              return ''; 
          },

          parseCommentTitle(comment) {
            const result = {
              type: '',
              series: '',
              name: '',
              author: 'Vô danh',
            };

            // Regex mới để bắt tiêu đề 【Sách Thế Giới】【Hệ liệt】【Tác giả】
            const matchExtendedWB = comment.match(/^【(Thiên Phú|ThiênPhú|Thiên phú|Thiênphú|thiên Phú|thiênPhú|thiên phú|thiênphú|Xuất Thân|XuấtThân|Xuất thân|Xuấtthân|xuất Thân|xuấtThân|xuất thân|xuấtthân|Khởi Đầu Mẫu|KhởiĐầuMẫu|Khởi Đầu Mẫu|Khởiđầumẫu|Khởi Đầu Mẫu|khởiđầumẫu|Thế Giới|ThếGiới|Thế giới|Thếgiới|thế Giới|thếGiới|thế giới|thếgiới)】【([^】]+)】【([^】]+)】(.+)$/);
            const match1 = comment.match(/^【(Thiên Phú|ThiênPhú|Thiên phú|Thiênphú|thiên Phú|thiênPhú|thiên phú|thiênphú|Xuất Thân|XuấtThân|Xuất thân|Xuấtthân|xuất Thân|xuấtThân|xuất thân|xuấtthân|Khởi Đầu Mẫu|KhởiĐầuMẫu|Khởi Đầu Mẫu|Khởiđầumẫu|Khởi Đầu Mẫu|khởiđầumẫu|Thế Giới|ThếGiới|Thế giới|Thếgiới|thế Giới|thếGiới|thế giới|thếgiới)】【([^】]+)】([^【]+)【([^】]+)】$/);
            const match2 = comment.match(/^【(Thiên Phú|ThiênPhú|Thiên phú|Thiênphú|thiên Phú|thiênPhú|thiên phú|thiênphú|Xuất Thân|XuấtThân|Xuất thân|Xuấtthân|xuất Thân|xuấtThân|xuất thân|xuấtthân|Khởi Đầu Mẫu|KhởiĐầuMẫu|Khởi Đầu Mẫu|Khởiđầumẫu|Khởi Đầu Mẫu|khởiđầumẫu|Thế Giới|ThếGiới|Thế giới|Thếgiới|thế Giới|thếGiới|thế giới|thếgiới)】([^【]+)【([^】]+)】$/);

            if (matchExtendedWB) {
                result.type = matchExtendedWB[1];
                result.series = matchExtendedWB[2];
                result.author = matchExtendedWB[3];
                result.name = matchExtendedWB[4].trim();
            } else if (match1) {
              result.type = match1[1];
              result.series = match1[2];
              result.name = match1[3].trim();
              result.author = match1[4];
            } else if (match2) {
              result.type = match2[1];
              result.name = match2[2].trim();
              result.author = match2[3];
            } else {
              const oldMatch = comment.match(/^【(Thiên Phú|ThiênPhú|Thiên phú|Thiênphú|thiên Phú|thiênPhú|thiên phú|thiênphú|Xuất Thân|XuấtThân|Xuất thân|Xuấtthân|xuất Thân|xuấtThân|xuất thân|xuấtthân|Khởi Đầu Mẫu|KhởiĐầuMẫu|Khởi Đầu Mẫu|Khởiđầumẫu|Khởi Đầu Mẫu|khởiđầumẫu|Thế Giới|ThếGiới|Thế giới|Thếgiới|thế Giới|thếGiới|thế giới|thếgiới)】(.+)$/);
              if (oldMatch) {
                result.type = oldMatch[1];
                result.name = oldMatch[2].trim();
              }
            }

            if (!comment) return result;
           // Chuẩn hóa dấu ngoặc
            let safeComment = comment.trim().replace(/\[/g, '【').replace(/\]/g, '】');
            const firstTagMatch = safeComment.match(/^【([^】]+)】/);

            if (!firstTagMatch) {
                result.name = comment;
                return result;
            }

            const rawType = firstTagMatch[1];
            const normalizedType = this.normalizeType(rawType);

            // Nếu thẻ đầu tiên không phải là Loại (Thiên phú/Xuất thân...), thì coi như đó là tên bình thường hoặc loại không hỗ trợ
            if (!normalizedType) {
                result.name = comment;
                return result;
            }

            result.type = normalizedType;

            // 3. Phân tích phần còn lại sau thẻ Loại
            let remaining = safeComment.substring(firstTagMatch[0].length).trim();

            // Kiểm tra xem có thẻ Hệ liệt 【Series】 tiếp theo không?
            const secondTagMatch = remaining.match(/^【([^】]+)】/);
            if (secondTagMatch) {
                // Nếu có thẻ thứ 2 ngay sau thẻ 1, đó là Hệ liệt
                result.series = secondTagMatch[1].trim();
                remaining = remaining.substring(secondTagMatch[0].length).trim();
            }

            // Kiểm tra xem có thẻ Tác giả 【Author】 ở đầu phần còn lại không? (Dạng: 【Loại】【Hệ liệt】【Tác giả】 Tên)
            const thirdTagMatch = remaining.match(/^【([^】]+)】/);
            if (thirdTagMatch) {
                 result.author = thirdTagMatch[1].trim();
                 remaining = remaining.substring(thirdTagMatch[0].length).trim();
                 result.name = remaining; // Phần còn lại là Tên
            } else {
                // Kiểm tra xem có thẻ Tác giả ở CUỐI cùng không? (Dạng: 【Loại】 Tên 【Tác giả】)
                // Regex tìm 【Nội dung】 ở cuối chuỗi
                const authorAtEndMatch = remaining.match(/【([^】]+)】$/);
                if (authorAtEndMatch) {
                    result.author = authorAtEndMatch[1].trim();
                    // Tên là phần từ đầu đến trước thẻ tác giả
                    result.name = remaining.substring(0, remaining.length - authorAtEndMatch[0].length).trim();
                } else {
                    // Không tìm thấy thẻ tác giả, toàn bộ phần còn lại là Tên
                    result.name = remaining;
                }
            }
            return result;
          },

          generateCommentTitle(type, name, author, series = '') {
            const typeMap = { talent: 'Thiên Phú', background: 'Xuất Thân', preset: 'Khởi Đầu Mẫu', worldbook: 'Sách Thế Giới' };
            const typeText = typeMap[type] || type;
            const seriesString = String(series || '').trim();
            const safeName = name.trim();
            const safeAuthor = author ? author.trim() : 'Vô danh';

            if (seriesString) {
              return `【${typeText}】【${seriesString}】${safeName}【${safeAuthor}】`;
            } else {
              if (type === 'worldbook') {
                  return `【${typeText}】${safeName}`;
              }
              return `【${typeText}】${safeName}【${safeAuthor}】`;
            }
          },

          async loadAllData() {
            try {
              // FIX: Gọi hàm phát hiện tên sách trước khi tải
              await this.detectActiveLorebook();
              let allEntries;
              try {
                allEntries = await TavernHelper.getWorldbook(this.LOREBOOK_NAME);
              } catch (e) {
                console.warn(`Sách Thế Giới "${this.LOREBOOK_NAME}" không tồn tại hoặc tải thất bại, đang thử tạo mới...`, e);
                const created = await TavernHelper.createWorldbook(this.LOREBOOK_NAME);
                if (created) {
                  console.log(`Sách Thế Giới "${this.LOREBOOK_NAME}" tạo thành công.`);
                  allEntries = [];
                } else {
                  throw new Error(`Không thể tạo Sách Thế Giới "${this.LOREBOOK_NAME}".`);
                }
              }

              if (!allEntries) allEntries = [];

              const talents = [];
              const backgrounds = [];
              const presets = [];
              const worldbookEntries = [];

              if (allEntries.length === 0) {
                console.log('Sách Thế Giới trống hoặc không tồn tại.');
                return { talents: [], backgrounds: [], presets: [], worldbookEntries: [], isEmpty: true };
              }

              for (const entry of allEntries) {
                try {
                  const titleInfo = this.parseCommentTitle(entry.name);
                  // Bỏ qua các mục không phải là Thiên Phú/Xuất Thân/Khởi Đầu Mẫu/Thế Giới
                  if (!titleInfo.type && !['Thiên Phú', 'Xuất Thân', 'Khởi Đầu Mẫu', 'Thế Giới'].includes(titleInfo.type)) {
                     worldbookEntries.push(entry);
                     continue;
                  }

                  // Chỉ parse YAML nếu là loại dữ liệu chúng ta quan tâm
                  const yamlData = YAMLParser.parse(entry.content);

                  // Kiểm tra loại entry dựa trên Type đã được chuẩn hóa
                  if (titleInfo.type === 'Thiên Phú') {
                      const parsedName = titleInfo.name;
                      talents.push({
                        id: parsedName,
                        name: parsedName || this.findFuzzyValue(yamlData, ['Tên', 'name']) || '',
                        author: titleInfo.author || this.findFuzzyValue(yamlData, ['Tác giả', 'Tác_giả', 'author']) || '',
                        quality: this.findFuzzyValue(yamlData, ['Phẩm giai', 'Phẩm_giai', 'quality', '品阶']) || '',
                        cost: parseInt(this.findFuzzyValue(yamlData, ['Tiêu hao điểm số', 'Tiêu_hao_điểm_số', 'Điểm số tiêu hao', 'Điểm_số_tiêu_hao', 'Tiêu hao', 'Tiêu_hao', 'cost', '消耗分数'])) || 0,
                        series: titleInfo.series || this.findFuzzyValue(yamlData, ['Hệ liệt', 'Hệ_liệt', 'series', '系列']) || '',
                        description: this.findFuzzyValue(yamlData, ['Mô tả', 'Mô_tả', 'description', '描述']) || '',
                        isFromWorldBook: true,
                        originalComment: entry.name,
                        uid: entry.uid,
                      });
                      worldbookEntries.push(entry);
                  } else if (titleInfo.type === 'Xuất Thân') {
                      const parsedName = titleInfo.name;
                      backgrounds.push({
                        id: parsedName,
                        name: parsedName || this.findFuzzyValue(yamlData, ['Tên', 'name']) || '',
                        author: titleInfo.author || this.findFuzzyValue(yamlData, ['Tác giả', 'Tác_giả', 'author']) || '',
                        quality: this.findFuzzyValue(yamlData, ['Phẩm giai', 'Phẩm_giai', 'quality', '品阶']) || '',
                        series: titleInfo.series || this.findFuzzyValue(yamlData, ['Hệ liệt', 'Hệ_liệt', 'series', '系列']) || '',
                        description: this.findFuzzyValue(yamlData, ['Mô tả', 'Mô_tả', 'description', '描述']) || '',
                        initialResources: this.findFuzzyValue(yamlData, ['Tài nguyên khởi đầu', 'Tài_nguyên_khởi_đầu', 'initialResources', '初始资源']) || [],
                        isFromWorldBook: true,
                        originalComment: entry.name,
                        uid: entry.uid,
                      });
                      worldbookEntries.push(entry);
                  } else if (titleInfo.type === 'Khởi Đầu Mẫu') {
                      const parsedName = titleInfo.name;
                      presets.push({
                        id: parsedName,
                        name: parsedName || this.findFuzzyValue(yamlData, ['Tên', 'name']) || '',
                        author: titleInfo.author || this.findFuzzyValue(yamlData, ['Tác giả', 'Tác_giả', 'author']) || '',
                        points: parseInt(this.findFuzzyValue(yamlData, ['Điểm số', 'Điểm_số', 'points', '分数'])) || 40,
                        series: titleInfo.series || this.findFuzzyValue(yamlData, ['Hệ liệt', 'Hệ_liệt', 'series', '系列']) || '',
                        description: this.findFuzzyValue(yamlData, ['Mô tả', 'Mô_tả', 'description', '描述']) || '',
                        attributes: this.findFuzzyValue(yamlData, ['Phân bổ thuộc tính', 'Phân_bổ_thuộc_tính', 'attributes', '属性分配']) || {},
                        requiredTalents: this.findFuzzyValue(yamlData, ['Thiên phú bắt buộc', 'Thiên_phú_bắt_buộc', 'requiredTalents', '绑定天赋', '强制天赋']) || [],
                        optionalTalents: this.findFuzzyValue(yamlData, ['Thiên phú tùy chọn', 'Thiên_phú_tùy_chọn', 'optionalTalents', '可选天赋']) || [],
                        isFromWorldBook: true,
                        originalComment: entry.name,
                        uid: entry.uid,
                        enabled: entry.enabled,
                      });
                      worldbookEntries.push(entry);
                  } else {
                    worldbookEntries.push(entry);
                  }
                } catch (e) {
                  console.warn('Phân tích mục Sách Thế Giới thất bại:', entry.name, e);
                }
              }
              return { talents, backgrounds, presets, worldbookEntries, isEmpty: false };
            } catch (error) {
              console.error('Tải dữ liệu từ Sách Thế Giới thất bại:', error);
              return { talents: [], backgrounds: [], presets: [], worldbookEntries: [], isEmpty: true };
            }
          },

          async _saveOrUpdateWith(updaterFn) {
              try {
                // Đảm bảo tên sách đã được phát hiện trước khi lưu
                  if (this.LOREBOOK_NAME === '1 Quy Khư') await this.detectActiveLorebook();
                  await TavernHelper.updateWorldbookWith(this.LOREBOOK_NAME, updaterFn);
                  return true;
              } catch (error) {
                  console.error('Cập nhật Sách Thế Giới thất bại:', error);
                  return false;
              }
          },

          async saveTalentOrBackground(itemData, type) {
            const entryToSave = { ...itemData }; 

            entryToSave.name = this.generateCommentTitle(type, itemData.name, itemData.author, itemData.series);

            if (type === 'talent') {
                entryToSave.content = YAMLParser.stringify({
                    Phẩm_giai: itemData.quality || '',
                    Tiêu_hao_điểm_số: itemData.cost || 0,
                    Hệ_liệt: itemData.series || '',
                    Mô_tả: itemData.description || '',
                });
            } else { // background
                entryToSave.content = YAMLParser.stringify({
                    Phẩm_giai: itemData.quality || '',
                    Hệ_liệt: itemData.series || '',
                    Mô_tả: itemData.description || '',
                    Tài_nguyên_khởi_đầu: itemData.initialResources || [],
                });
            }

            if (typeof entryToSave.enabled === 'undefined') entryToSave.enabled = false;
            if (typeof entryToSave.strategy === 'undefined') entryToSave.strategy = { type: 'selective', keys: [itemData.name] };
            if (typeof entryToSave.position === 'undefined') entryToSave.position = { type: 'before_character_definition', order: type === 'talent' ? 100 : 200 };

            // Dọn dẹp các thuộc tính dành riêng cho frontend
            const nonWbProps = ['cost', 'series', 'quality', 'description', 'initialResources', 'author', 'id', 'isFromWorldBook', 'originalComment'];
            nonWbProps.forEach(prop => delete entryToSave[prop]);

            return this._saveOrUpdateWith(worldbook => {
                const index = entryToSave.uid ? worldbook.findIndex(e => String(e.uid) === String(entryToSave.uid)) : -1;
                if (index > -1) {
                    worldbook[index] = { ...worldbook[index], ...entryToSave };
                } else {
                    delete entryToSave.uid; 
                    worldbook.push(entryToSave);
                }
                return worldbook;
            });
          },

          async savePreset(presetData) {
            const entryToSave = { ...presetData };

            entryToSave.name = this.generateCommentTitle('preset', presetData.name, presetData.author, presetData.series);

            entryToSave.content = YAMLParser.stringify({
              Điểm_số: presetData.points || 40,
              Hệ_liệt: presetData.series || '',
              Mô_tả: presetData.description || '',
              Phân_bổ_thuộc_tính: presetData.attributes || {},
              Thiên_phú_bắt_buộc: presetData.requiredTalents || [],
              Thiên_phú_tùy_chọn: presetData.optionalTalents || [],
            });

            if (typeof entryToSave.enabled === 'undefined') entryToSave.enabled = false;
            if (typeof entryToSave.strategy === 'undefined') entryToSave.strategy = { type: 'selective', keys: [presetData.name] };
            if (typeof entryToSave.position === 'undefined') entryToSave.position = { type: 'before_character_definition', order: 300 };

            const nonWbProps = ['points', 'series', 'description', 'attributes', 'requiredTalents', 'optionalTalents', 'author', 'id', 'isFromWorldBook', 'originalComment'];
            nonWbProps.forEach(prop => delete entryToSave[prop]);

            return this._saveOrUpdateWith(worldbook => {
              const index = entryToSave.uid ? worldbook.findIndex(e => String(e.uid) === String(entryToSave.uid)) : -1;
              if (index > -1) {
                worldbook[index] = { ...worldbook[index], ...entryToSave };
              } else {
                delete entryToSave.uid;
                worldbook.push(entryToSave);
              }
              return worldbook;
            });
          },

          async saveWorldBookEntry(entryData) {
            return this._saveOrUpdateWith(worldbook => {
              const entryIndex = entryData.uid ? worldbook.findIndex(e => String(e.uid) === String(entryData.uid)) : -1;
              if (entryIndex > -1) {
                worldbook[entryIndex] = { ...worldbook[entryIndex], ...entryData };
              } else {
                worldbook.push(entryData);
              }
              return worldbook;
            });
          },

          async deleteEntryByUid(uid) {
            if (typeof uid === 'undefined' || uid === null) {
                console.error('Đã cố gắng xóa một mục với UID không hợp lệ');
                return false;
            }
            try {
                return await this._saveOrUpdateWith(worldbook => worldbook.filter(e => String(e.uid) !== String(uid)));
            } catch (error) {
                console.error(`Xóa mục Sách Thế Giới thất bại với UID: ${uid}`, error);
                return false;
            }
          },
        };

