    { id: 'Thiên Phú Tiên Phẩm - Kiếm Đạo Chí Tôn', name: 'Thiên Phú Tiên Phẩm - Kiếm Đạo Chí Tôn', author: 'Mộng Tinh', series: '', cost: 0, quality: 'Tiên phẩm', description: 'Có thiên phú vô song về phương diện kiếm đạo. (Đạo tâm +300, Pháp lực +200)', unlocked: false },
    { id: 'Diễn Mộng Quy Khư Linh Căn', name: 'Diễn Mộng Quy Khư Linh Căn', author: 'Mộng Tinh', series: '', cost: 0, quality: 'Thần phẩm', description: '1. Có thể nhìn thấy cực kỳ mờ ảo các đoạn ngắn tương lai trong vòng 7 ngày.\n**2. Chịu đựng nỗi đau Quy Khư, ngày linh hồn tiêu tan chính là lúc Quy Khư**\n**2.1 Mỗi 7 ngày cần chịu đựng Quy Khư, cực kỳ đau đớn, kéo dài hai giờ, linh hồn sẽ mờ đi một chút để nuôi dưỡng Diễn Mộng Quy Khư Linh Căn, sau đó Mộng Diễn Quy Khư Linh Căn cũng sẽ mạnh lên một chút**\n3. Thiên phú tu luyện cực mạnh\n- Diễn Mộng Quy Khư Linh Căn, người sở hữu bẩm sinh phải chịu cái giá: Quy Khư\n- Khi vật chủ của Diễn Mộng Quy Khư Linh Căn Quy Khư, nó mới nở rộ sự mạnh mẽ thực sự\n- Diễn Mộng Quy Khư Linh Căn sau khi Quy Khư không có tác dụng phụ, mỗi ngày có thể dự đoán một lần bất kỳ tương lai nào trong 7 ngày, tốc độ tu luyện cực nhanh, có thể tăng cường thực lực đáng kể\n- Quyền sở hữu Diễn Mộng Quy Khư Linh Căn hoàn toàn do vật chủ quyết định, không ai có thể cướp đoạt hay ép buộc, có thể nhất niệm tự bạo linh căn. (Thần hải +500, tốc độ tu luyện cực nhanh, nhưng đi kèm rủi ro lớn)', unlocked: false },
    { id: 'Tàn Tinh Biến', name: 'Tàn Tinh Biến', author: 'Mộng Tinh', series: '', cost: 0, quality: 'Thần phẩm', description: 'Lập tức bộc phát thực lực vượt qua bản thân một đại cảnh giới, không tác dụng phụ. Đây là thứ Mộng Tinh có được tại một nơi Ẩn Cảnh Tiềm Hóa.', unlocked: false },
    { id: 'Huyền Mộng Trảm', name: 'Huyền Mộng Trảm', author: 'Mộng Tinh', series: '', cost: 0, quality: 'Thần phẩm', description: 'Kỹ năng dùng một lần, có thể lập tức trảm sát kẻ địch không cao hơn bản thân hai đại cảnh giới. Một ngày có thể sử dụng một lần.', unlocked: false },
    { id: 'Hư Không Kiếp Biến Sinh Tử Kinh', name: 'Hư Không Kiếp Biến Sinh Tử Kinh', author: 'Mộng Tinh', series: '', cost: 0, quality: 'Thần phẩm', description: 'Mộng Tinh lập tức nhớ lại và ngộ thấu bộ công pháp này từ động phủ của một cường giả Phi Thăng kỳ bí ẩn, tiến độ tu luyện tăng mạnh, khoảng một đại cảnh giới, sau đó tốc độ tu luyện tăng mạnh, hệ số tu tiên tăng 1.5, tấn công tăng mạnh, đòn tấn công có thể lợi dụng hư không để kiếp biến, tạo hóa sinh tử, giơ tay nhấc chân là vết nứt hư không **Trạng thái thường trú**.', unlocked: false },
    { id: 'Hư Không Kiếp Biến Luân Hồi Kinh', name: 'Hư Không Kiếp Biến Luân Hồi Kinh', author: 'Mộng Tinh', series: '', cost: 0, quality: 'Thần phẩm', description: 'Mộng Tinh lập tức nhớ lại và ngộ thấu công pháp này, tốc độ tăng cực lớn, có thể nhất niệm vượt qua không gian đến bất kỳ nơi nào ghi nhớ trong não. Nhưng phương pháp này cần tiêu hao hệ số tu tiên/tiềm lực, Mộng Tinh trừ khi gặp tình huống quan trọng, nếu không chỉ sử dụng chức năng tăng tốc độ.', unlocked: false },
    { id: 'Thiên Địa Đồng Thọ, Tạo Hóa Nghịch Sinh', name: 'Thiên Địa Đồng Thọ, Tạo Hóa Nghịch Sinh', author: 'Mộng Tinh', series: '', cost: 0, quality: 'Thần phẩm', description: 'Mộng Tinh ngộ ra đạo pháp "Thiên địa đồng thọ, tạo hóa nghịch sinh", có thể bỏ qua cảnh giới, bỏ qua phòng thủ, một ngày có thể thi triển ba lần, vô điều kiện kích sát kẻ địch.', unlocked: false },
