    { id: 'Lùi Ra Sau Mọi Người', name: 'Lùi Ra Sau Mọi Người', author: 'Mộng Tinh', series: '', cost: 10, quality: 'Trung phẩm', description: 'Khi gặp nguy hiểm tự động lùi ra sau mọi người, rất khó bị kẻ địch phát hiện ngay lập tức. (Không tốc +20)' },
    { id: 'Song Sinh Chi Thể', name: 'Song Sinh Chi Thể', author: 'Mộng Tinh', series: '', cost: 40, quality: 'Thiên phẩm', description: 'Có thể phân tách ra một thân xác huyết nhục khác giới tính, ý thức, cảm nhận, suy nghĩ của nó đều nhất quán với bản thể, tu luyện gấp đôi, vui vẻ gấp đôi. (Tốc độ tu luyện tăng 50%)' },
    { id: 'Hoang Cổ Thánh Thể', name: 'Hoang Cổ Thánh Thể', author: 'Mộng Tinh', series: '', cost: 50, quality: 'Tiên phẩm', description: '(Già Thiên) Một loại thể chất cường đại, khí huyết sung túc, nhục thân vô song, là thánh thể sinh ra để chiến đấu. (Pháp lực +200, Đạo tâm +50)' },
    { id: 'Gia Tộc Thủy Tổ', name: 'Gia Tộc Thủy Tổ', author: 'Mộng Tinh', series: '', cost: 30, quality: 'Cực phẩm', description: 'Thuộc tính và cường độ năng lực bản thân có thể tăng cường theo số lượng thành viên gia tộc, đồng thời thành viên tu vi cao trong gia tộc càng nhiều, sẽ tăng phúc cho tất cả thành viên trong gia tộc. (Khí vận khởi đầu +100)' },
    { id: 'Người Duy Trì Nòi Giống', name: 'Người Duy Trì Nòi Giống', author: 'Mộng Tinh', series: '', cost: 25, quality: 'Thượng phẩm', description: 'Thuộc tính và cường độ năng lực có thể tăng cường theo số lượng hậu duệ. (Khí vận khởi đầu +50)' },
    { id: 'Định Bất Phụ Khanh', name: 'Định Bất Phụ Khanh', author: 'Mộng Tinh', series: '', cost: 20, quality: 'Thượng phẩm', description: 'Đạo lữ từng song tu hoặc hứa hẹn sẽ gieo mầm lửa trong lòng, sau đó sẽ diễn hóa dựa trên cách xử thế và bồi dưỡng của user, cực đoan thì là huyết nhục giao hòa, tốt đẹp thì là thần tiên quyến lữ. (Đạo tâm +50)' },
    { id: 'Đại Gian Đại Ác', name: 'Đại Gian Đại Ác', author: 'Mộng Tinh', series: '', cost: 15, quality: 'Trung phẩm', description: 'Bạn trời sinh đã là ác nhân, ác hành của bạn bị thiên đạo bỏ qua, tu vi không chỉ có thể thông qua tu luyện, mà còn có thể thông qua việc ác độc để thu hoạch. (Đạo tâm -50, nhưng nhận thêm tu vi khi làm ác)' },
    { id: 'Kẻ Săn Tình Yêu', name: 'Kẻ Săn Tình Yêu', author: 'Mộng Tinh', series: '', cost: 35, quality: 'Thiên phẩm', description: 'Có thể bắt giữ người đang hôn mê không thể phản kháng, khiến người đó yêu bạn, thỏa mãn vô điều kiện bất kỳ yêu cầu nào của bạn. (Đạo tâm +150)' },
    { id: 'Chú Huyết Kiếm Khí', name: 'Chú Huyết Kiếm Khí', author: 'Mộng Tinh', series: '', cost: 40, quality: 'Thiên phẩm', description: 'Bạn trời sinh đã sở hữu kiếm khí này, kiếm khí này có thể cắn nuốt tu vi huyết nhục kẻ địch để hồi phục thương thế cho bản thân, đồng thời kiếm khí này bỏ qua phòng thủ linh lực. (Pháp lực +200)' },
    { id: 'Quân Diễm', name: 'Quân Diễm', author: 'Mộng Tinh', series: '', cost: 30, quality: 'Cực phẩm', description: 'Bạn trời sinh Hỏa Linh Chi Thể, hỏa thuộc tính pháp thuật thi triển có thể thiêu đốt linh lực càng đốt càng mạnh, nhưng bản thân cũng chỉ có thể tu luyện công pháp hỏa thuộc tính và sử dụng trang bị hỏa thuộc tính. (Pháp lực +150)' },
    { id: 'Hư Không Hành Giả', name: 'Hư Không Hành Giả', author: 'Mộng Tinh', series: '', cost: 35, quality: 'Thiên phẩm', description: 'Bạn trời sinh thân hòa với không gian, có thể dễ dàng xuyên qua khe nứt không gian, thực hiện nhảy không gian khoảng cách ngắn. (Không tốc +150)' },
    { id: 'Lôi Phạt Chi Thể', name: 'Lôi Phạt Chi Thể', author: 'Mộng Tinh', series: '', cost: 35, quality: 'Thiên phẩm', description: 'Cơ thể bạn là con cưng của lôi điện, không chỉ có thể hấp thu lôi điện chi lực làm của riêng, lôi pháp thi triển cũng tăng gấp đôi uy lực. (Pháp lực +150)' },
    { id: 'Bất Tử Chi Thân', name: 'Bất Tử Chi Thân', author: 'Mộng Tinh', series: '', cost: 50, quality: 'Tiên phẩm', description: 'Chỉ cần còn một giọt máu tồn tại, bạn có thể tích huyết trùng sinh, sở hữu khả năng hồi phục gần như bất tử, nhưng mỗi lần trùng sinh đều sẽ tiêu hao lượng lớn sinh mệnh bản nguyên. (Pháp lực +250)' },
    { id: 'Tâm Nhãn', name: 'Tâm Nhãn', author: 'Mộng Tinh', series: '', cost: 25, quality: 'Thượng phẩm', description: 'Bạn nhìn thấu hư vọng, chỉ thẳng bản tâm. Có thể nhìn thấu cảm xúc và suy nghĩ chân thật của người khác, không dễ bị ảo thuật và lời nói dối mê hoặc. (Thần hải +100)' },
    { id: 'Thôi Diễn Vạn Vật', name: 'Thôi Diễn Vạn Vật', author: 'Mộng Tinh', series: '', cost: 40, quality: 'Thiên phẩm', description: 'Bạn sở hữu năng lực thôi diễn siêu phàm, có thể dựa trên thông tin đã biết để thôi diễn phần tiếp theo của công pháp, sơ hở của trận pháp, thậm chí một khả năng nào đó trong tương lai. (Thần hải +200)' },
    { id: 'Thiên Đạo Thù Cần', name: 'Thiên Đạo Thù Cần', author: 'Mộng Tinh', series: '', cost: 15, quality: 'Trung phẩm', description: 'Sự nỗ lực của bạn luôn có hồi báo, khi tu luyện và cảm ngộ, có tỷ lệ nhận được thu hoạch thêm. (Khí vận +50)' },
    { id: 'Chúng Sinh Nguyện Lực', name: 'Chúng Sinh Nguyện Lực', author: 'Mộng Tinh', series: '', cost: 30, quality: 'Cực phẩm', description: 'Bạn có thể thu thập nguyện lực của tín đồ, chuyển hóa thành sức mạnh bản thân, tín đồ càng nhiều, thực lực của bạn càng mạnh. (Đạo tâm +150)' },
    { id: 'Đoạt Xá', name: 'Đoạt Xá', author: 'Mộng Tinh', series: '', cost: 20, quality: 'Thượng phẩm', description: 'Khi nhục thân của bạn bị hủy, thần hồn của bạn có thể đoạt xá thân xác người khác, nhưng có rủi ro thất bại nhất định, và sẽ sinh ra bài xích với nhục thân mới. (Thần hải +50)' },
    { id: 'Binh Chủ', name: 'Binh Chủ', author: 'Mộng Tinh', series: '', cost: 25, quality: 'Thượng phẩm', description: 'Bạn trời sinh có duyên với binh khí, bất kỳ binh khí nào trong tay bạn đều có thể phát huy mười hai phần uy lực, đồng thời có thể nhanh chóng lĩnh ngộ đạo và lý chứa trong binh khí. (Pháp lực +100)' },
    { id: 'Chưởng Thiên Bình', name: 'Chưởng Thiên Bình', author: 'Mộng Tinh', series: '', cost: 50, quality: 'Tiên phẩm', description: '(Phàm Nhân Tu Tiên Truyện) Bạn tình cờ có được một cái bình nhỏ màu xanh thần bí, có thể thôi sinh linh thực, tăng tốc sinh trưởng. (Khí vận +250)' },
    { id: 'Nhất Nặc Thiên Kim', name: 'Nhất Nặc Thiên Kim', author: 'Mộng Tinh', series: '', cost: 10, quality: 'Trung phẩm', description: 'Bạn sở hữu một đạo lữ vô cùng chung thủy với bạn, cô ấy/anh ấy sẽ là hậu phương vững chắc nhất của bạn. (Khí vận +20)' },
    { id: 'Tai Họa Chuyển Dời', name: 'Tai Họa Chuyển Dời', author: 'Mộng Tinh', series: '', cost: 20, quality: 'Thượng phẩm', description: 'Mỗi khi phán định khí vận của bạn thất bại, đều sẽ ngẫu nhiên chuyển sang cho một đơn vị không phải đồng minh bên cạnh bạn. (Khí vận -50, nhưng có thể chuyển dời sự kiện tiêu cực)' },
    { id: 'Đại Lực Chân Võ Thể', name: 'Đại Lực Chân Võ Thể', author: 'Mộng Tinh', series: '', cost: 40, quality: 'Thiên phẩm', description: 'Thánh thể thể tu cổ xưa, dùng sức mạnh nhục thân thuần túy đối ứng cảnh giới tu vi, sở hữu khả năng tự lành kinh khủng và khả năng chiến đấu bền bỉ. (Pháp lực +200)' },
    { id: 'Khuynh Quốc Khuynh Thành', name: 'Khuynh Quốc Khuynh Thành', author: 'Mộng Tinh', series: '', cost: 15, quality: 'Trung phẩm', description: 'Mị lực của bạn vô song, đủ để khiến kẻ ý chí không kiên định trầm luân, vì bạn mà si, vì bạn mà cuồng. (Khí vận +50)' },
    { id: 'Chân Long Huyết Mạch', name: 'Chân Long Huyết Mạch', author: 'Mộng Tinh', series: '', cost: 35, quality: 'Thiên phẩm', description: 'Trong cơ thể bạn chảy dòng máu Chân Long, theo tu vi tăng lên, bạn sẽ dần thức tỉnh thiên phú thần thông của Long tộc, cuối cùng thậm chí có thể hóa thân thành rồng. (Pháp lực +150)' },
    { id: 'Thiên Đố Anh Tài', name: 'Thiên Đố Anh Tài', author: 'Mộng Tinh', series: '', cost: 5, quality: 'Hạ phẩm', description: 'Ngộ tính và thiên phú của bạn vượt xa người thường, tu luyện tiến bộ cực nhanh, nhưng thiên đạo không dung, bạn thường không sống quá ba mươi tuổi. (Thần hải +50, Đạo tâm +50, Khí vận -100)' },
    { id: 'Quỷ Đạo Luân Hồi', name: 'Quỷ Đạo Luân Hồi', author: 'Mộng Tinh', series: '', cost: 20, quality: 'Thượng phẩm', description: 'Cái chết không phải là kết thúc. Sau khi chết hồn phách bạn có thể không vào luân hồi, ở lại quỷ đạo, thông qua hút oán niệm ngưng tụ lại hồn thể, nhưng sau đó chỉ có thể tu hành công pháp quỷ đạo. (Thần hải +50)' },
    { id: 'Giới Tử Động Thiên', name: 'Giới Tử Động Thiên', author: 'Mộng Tinh', series: '', cost: 30, quality: 'Cực phẩm', description: 'Cơ thể bạn trời sinh ẩn chứa một phương tiểu thế giới, có thể trốn vào đó bất cứ lúc nào, cũng có thể bồi dưỡng linh thực, nuôi dưỡng linh thú trong đó. (Không tốc +150)' },
    { id: 'Địa Tam Tài', name: 'Địa Tam Tài', author: 'Mộng Tinh', series: '', cost: 25, quality: 'Thượng phẩm', description: 'Bạn trời sinh có ngộ tính và thiên phú cực cao với các nguyên tố Thổ, Mộc, Thủy, linh căn thiên hướng phòng ngự, thi triển pháp thuật loại này tiêu hao ít hơn, uy lực lớn hơn. (Pháp lực +50, Đạo tâm +50)' },
    { id: 'Thiên Tam Tài', name: 'Thiên Tam Tài', author: 'Mộng Tinh', series: '', cost: 25, quality: 'Thượng phẩm', description: 'Bạn trời sinh có ngộ tính và thiên phú cực cao với các nguyên tố Phong, Lôi, Hỏa, linh căn thiên hướng tấn công, thi triển pháp thuật loại này tiêu hao ít hơn, uy lực lớn hơn. (Pháp lực +50, Không tốc +50)' },
    { id: 'Chư Ác Tận Quy', name: 'Chư Ác Tận Quy', author: 'Mộng Tinh', series: '', cost: 40, quality: 'Thiên phẩm', description: 'Đặc tính:\n- Vật chứa vĩnh kiếp: Tự động thu hút ác hồn trong vòng trăm mét, cưỡng chế hút vào cơ thể giam cầm\n- Tinh lọc oán lực: Tách ý thức ác hồn giữ lại ác ý thuần túy, chuyển hóa thành năng lượng dự trữ cho chú thuật\n- Xử lý hài cốt: Hồn phách sau khi bị vắt kiệt bị nghiền nát, quy về hư vô. (Thần hải +150, Đạo tâm -50)' },
    { id: 'Vu Nghi Yếm Thắng Chi Thuật', name: 'Vu Nghi Yếm Thắng Chi Thuật', author: 'Mộng Tinh', series: '', cost: 45, quality: 'Tiên phẩm', description: 'Đặc tính:\n- Vật chứa thiên sinh: Tự động hấp thu sáu loại cảm xúc tiêu cực Ai, Nộ, Hận, Đố, Tử, Ác và lưu trữ sâu trong linh hồn\n- Lò luyện cảm xúc: Cảm xúc tiêu cực tích lũy có thể chuyển hóa thành năng lượng thi thuật, khi tới giới hạn giải phóng thuật Yếm Thắng\n- Bản chất thuật pháp: Truyền thừa thất lạc thời đại bộ lạc hoang dã, chú thuật luật nhân quả vận hành bằng cảm xúc làm nhiên liệu, âm quỷ ác độc và độc lập với hệ thống linh khí\nThức thuật:\n- Ai · Mạc Đại Vu Tâm Tử: Dẫn động hối hận cả đời mục tiêu, khiến đạo tâm tan rã linh trí chôn vùi\n- Nộ · Bạt Kiếm Khởi Hao Lai: Thắp lên ngọn lửa điên cuồng, thiêu rụi thần trí người chịu thuật khiến họ vĩnh viễn rơi vào điên loạn\n- Hận · Phụ Thảo Vô Huỳnh Hỏa: Gieo Đồng Mệnh Chú lên túc địch, khi kích hoạt cả hai bên hồn phi phách tán\n- Đố · Thị Dục Bản Vô Tính: Cấu trúc ống dẫn vô hình, liên tục hút đi sức mạnh người chịu thuật nuôi dưỡng người thi chú\n- Tử · Tư Nhân Dĩ Minh Minh: Ngâm xướng Hoàng Tuyền Trấn Hồn Ca, xóa bỏ dương thọ tất cả người nghe, bao gồm cả người thi thuật\n- Ác · La Tụ Sái Xích Huyết: Dùng tinh huyết nuôi Vu Cổ Ngẫu Nhân, giáng tai kiếp ôn dịch xuống người bị nguyền rủa. (Đạo tâm -250, Thần hải +500)' },
    { id: 'Diệt Pháp · Bất Hưu', name: 'Diệt Pháp · Bất Hưu', author: 'Mộng Tinh', series: '', cost: 50, quality: 'Thần phẩm', description: 'Đặc tính Diệt Pháp:\n- Xiềng xích Tuyệt Linh: Hoàn toàn không thể tiến hành bất kỳ hành vi tu luyện hoặc thi pháp nào dựa vào linh khí\n- Đạo pháp chôn vùi: Khoảnh khắc tiếp xúc phá hủy pháp thuật/pháp khí/linh mạch tồn tại dựa vào hệ thống linh khí\n- Hồn phi phách tán: Khi chết hồn phách trực tiếp tan rã, không vào luân hồi\n- Hận hỏa liệu nguyên: Lúc lâm chung dẫn nổ tích oán của chúng sinh đối với tu tiên giả, dựa theo mức độ tội nghiệp của người tu hành, vĩnh viễn chuyển hóa cương vực tương ứng thành tử địa Tuyệt Linh\nĐặc tính Bất Hưu:\n- Quy tắc cốt lõi: "Mối hận của phàm nhân vĩnh viễn không ngừng nghỉ, thế giới này cuối cùng sẽ về thời đại Diệt Pháp"\n- Văn minh thay đổi: Vùng đất Tuyệt Linh trải qua số bảy bảy, sẽ thai nghén dạng sống thế hệ mới kế thừa toàn bộ thiên phú\n- Kết cục: Khi thế gian không còn linh khí, bạn sẽ hoàn toàn tan biến. (Không thể tu tiên, nhưng gây đòn đả kích hủy diệt cho tu tiên giả)' },
    { id: 'Lục Căn Bất Tịnh', name: 'Lục Căn Bất Tịnh', author: 'Mộng Tinh', series: '', cost: 15, quality: 'Trung phẩm', description: 'Tất cả tư chất linh căn của bạn đều được nâng cao, nhưng tạp niệm mọc thành bụi khiến niệm lực giảm mạnh, tinh lực cũng trở nên hạn chế hơn. (Tư chất linh căn tăng, Thần hải -20)' },
    { id: 'Lục Căn Thanh Tịnh', name: 'Lục Căn Thanh Tịnh', author: 'Mộng Tinh', series: '', cost: 15, quality: 'Trung phẩm', description: 'Tất cả tư chất linh căn của bạn có phần suy yếu, nhưng nhờ tâm không tạp niệm mà niệm lực mạnh mẽ dị thường, tinh lực cũng dồi dào hơn. (Tư chất linh căn giảm, Thần hải +40)' },
    { id: 'Linh Nhục Thôn Phệ', name: 'Linh Nhục Thôn Phệ', author: 'Mộng Tinh', series: '', cost: 25, quality: 'Thượng phẩm', description: 'Bạn có thể trực tiếp thôn phệ huyết nhục mục tiêu trên phương diện linh lực, và chuyển hóa thành sức mạnh bản thân. (Pháp lực +50, Đạo tâm -10)' },
    { id: 'Vận Mệnh Chi Hài', name: 'Vận Mệnh Chi Hài', author: 'Mộng Tinh', series: '', cost: 5, quality: 'Hạ phẩm', description: 'Thần hải của bạn trời sinh có một viên xúc xắc, bạn có thể kích hoạt phán định khí vận ném nó, nhưng dường như điểm số ném ra đều chẳng có tác dụng gì. (Khí vận dao động ngẫu nhiên)' },
    { id: 'Sát Thủ Chủng Loài', name: 'Sát Thủ Chủng Loài', author: 'Mộng Tinh', series: '', cost: 20, quality: 'Thượng phẩm', description: 'Bạn có thể thông qua việc liên tục săn giết một chủng loài đặc định nào đó, để không ngừng tăng cường năng lực tương ứng của bản thân. (Thiên phú có tính trưởng thành)' },
    { id: 'Ách Vận Quấn Thân', name: 'Ách Vận Quấn Thân', author: 'Mộng Tinh', series: '', cost: 0, quality: 'Hạ phẩm', description: 'Bạn bất kể làm chuyện gì, nếu kích hoạt phán định khí vận, kết quả đều sẽ là thất bại. (Khí vận -100)' },
    { id: 'Địch Trần Linh Thổ Thể', name: 'Địch Trần Linh Thổ Thể', author: 'Mộng Tinh', series: '', cost: 30, quality: 'Cực phẩm', description: 'Bạn mang trong mình Linh Thổ Chi Thể gột rửa trần uế, quanh thân lượn lờ địa khí hồn hậu, không chỉ khiến năng lực phòng ngự tăng lên đáng kể, còn làm cho tư chất Thổ hệ linh căn trở nên siêu phàm. Nhưng Thổ linh chi lực quá mức tinh thuần cũng áp chế sự trưởng thành của các linh căn thuộc tính khác. (Thiên hướng phòng ngự, cộng thêm Thổ linh căn)' },
    { id: 'Minh Âm Ất Hỏa Thể', name: 'Minh Âm Ất Hỏa Thể', author: 'Mộng Tinh', series: '', cost: 30, quality: 'Cực phẩm', description: 'Bạn thức tỉnh bản nguyên U Minh Âm Hỏa, trong cơ thể ẩn nấp ngọn lửa lạnh lẽo ăn mòn xương cốt thiêu đốt linh hồn, đồng thời cường hóa phòng ngự, đẩy tư chất Hỏa hệ linh căn lên cực hạn. Tuy nhiên Âm hỏa này bá đạo vô song, khiến cho các linh căn còn lại ảm đạm thất sắc. (Thiên hướng phòng ngự, cộng thêm Hỏa linh căn)' },
    { id: 'Thu Nguyên Bi Phong Thể', name: 'Thu Nguyên Bi Phong Thể', author: 'Mộng Tinh', series: '', cost: 30, quality: 'Cực phẩm', description: 'Bạn cùng chung nhịp thở với gió thu tiêu điều, gió bi thương hóa thành hộ thân cương khí tăng cường phòng ngự, tư chất Phong linh căn cũng như cuồng phong lăng không. Chỉ là Phong linh quá mức sắc bén, làm tổn thương căn cơ các hệ linh căn khác. (Thiên hướng phòng ngự, cộng thêm Phong linh căn)' },
    { id: 'Tử Cực Thực Lôi Thể', name: 'Tử Cực Thực Lôi Thể', author: 'Mộng Tinh', series: '', cost: 30, quality: 'Cực phẩm', description: 'Bạn dẫn Cửu Thiên Tử Lôi tôi luyện thể xác, khi lôi văn bao phủ cơ thể phòng ngự tăng gấp bội, tư chất Lôi linh căn tựa như thiên phạt giáng thế. Tuy nhiên Lôi uy bạo liệt áp chế ngũ hành, các linh căn còn lại như bị sét đánh trì trệ khó phát triển. (Thiên hướng phòng ngự, cộng thêm Lôi linh căn)' },
    { id: 'U Tứ Nhược Thủy Thể', name: 'U Tứ Nhược Thủy Thể', author: 'Mộng Tinh', series: '', cost: 30, quality: 'Cực phẩm', description: 'Bạn thông hiểu tính chất của U Tuyền Nhược Thủy, thủy thể nhu nhận hóa giải thế công vạn cân, tư chất Thủy linh căn tựa vực sâu cuộn trào. Tuy nhiên chí nhu chi thủy xâm nhiễm kinh mạch, linh căn hệ khác như sa vào vũng bùn khó thông suốt. (Thiên hướng phòng ngự, cộng thêm Thủy linh căn)' },
    { id: 'Cổ Đằng Bách Mộc Thể', name: 'Cổ Đằng Bách Mộc Thể', author: 'Mộng Tinh', series: '', cost: 30, quality: 'Cực phẩm', description: 'Bạn thừa kế sinh lực sinh sinh bất t息 của Thanh Đằng thượng cổ, khí thương mộc đúc thành lớp bảo vệ không thể phá vỡ, tư chất Mộc linh căn có thể so với thần mộc ngàn năm. Nhưng thảo mộc tinh nguyên độc chiếm linh khu, linh căn còn lại như gặp mùa hạn héo úa rũ rượi. (Thiên hướng phòng ngự, cộng thêm Mộc linh căn)' },
    { id: 'Bạch Hồng Quán Nhật', name: 'Bạch Hồng Quán Nhật', author: 'Mộng Tinh', series: '', cost: 20, quality: 'Thượng phẩm', description: 'Thương xuất như long, chỉ phá kinh hồng, tạo诣 thương pháp và chỉ pháp của bạn tựa như cầu vồng trắng xuyên mặt trời, phong mang thẳng thấu trời cao. (Chuyên tinh Thương, Chỉ pháp)' },
    { id: 'Đao Kiếm Song Tuyệt', name: 'Đao Kiếm Song Tuyệt', author: 'Mộng Tinh', series: '', cost: 25, quality: 'Thượng phẩm', description: 'Bạn tay trái cầm đao chẻ núi non, tay phải vung kiếm đoạn sông dài, cảnh giới đao kiếm song tuyệt đã tới hóa cảnh, hai loại binh khí trong tay bạn đều thành chí bảo sát phạt. (Chuyên tinh Đao, Kiếm pháp)' },
    { id: 'Võ Pháp Linh Đồng', name: 'Võ Pháp Linh Đồng', author: 'Mộng Tinh', series: '', cost: 30, quality: 'Cực phẩm', description: 'Bạn là Võ Pháp Linh Đồng được trời ban, các loại công pháp vừa chạm liền thông, giơ tay nhấc chân ngầm hợp chân ý thiên đạo, trong thế công tự mang cương sát phá địch. (Nâng cao khả năng lĩnh ngộ công pháp)' },
    { id: 'Khai Sơn Song Tuyệt', name: 'Khai Sơn Song Tuyệt', author: 'Mộng Tinh', series: '', cost: 25, quality: 'Thượng phẩm', description: 'Quyền bạn đấm nát đá tảng chưởng nứt vực sâu, khi quyền chưởng giao điệp khai sơn đoạn lưu, kình đạo cương mãnh vô song càng đúc thành khí giáp vô hình quanh thân. (Chuyên tinh Quyền, Chưởng pháp)' },
    { id: 'Vũ Khí Đại Sư', name: 'Vũ Khí Đại Sư', author: 'Mộng Tinh', series: '', cost: 30, quality: 'Cực phẩm', description: 'Đao thương kiếm kích đều là phần mở rộng tay chân bạn, phàm binh khí vào tay liền sinh cảm giác nhân khí hợp nhất, khi tu tập ba loại công pháp Kiếm Đao Thương như có thần trợ, tiến cảnh một ngày ngàn dặm. (Chuyên tinh Kiếm, Đao, Thương pháp)' },
    { id: 'Đa Tử Đa Phúc', name: 'Đa Tử Đa Phúc', author: 'Mộng Tinh', series: '', cost: 20, quality: 'Thượng phẩm', description: 'Có khả năng sinh sản siêu mạnh/khả năng khiến đối phương mang thai, đồng thời hậu duệ có thể kế thừa hoàn hảo thiên phú của bản thân. (Khí vận +50)' },
    { id: 'Thôi Miên APP', name: 'Thôi Miên APP', author: 'Mộng Tinh', series: '', cost: 35, quality: 'Thiên phẩm', description: 'Bạn có thể tiêu hao tài nguyên nhất định, cưỡng chế điều khiển tất cả sinh linh giống cái trong phạm vi hai đại cảnh giới thấp hơn mình, khiến độ hảo cảm đầy. Nhưng loại khống chế này có tỷ lệ bị phá giải, khi đó độ hảo cảm sẽ biến thành giá trị âm. (Đạo tâm +100, Thần hải +100)' },
    { id: 'Kiêu Hùng Chi Tư', name: 'Kiêu Hùng Chi Tư', author: 'Mộng Tinh', series: '', cost: 15, quality: 'Trung phẩm', description: 'Sức căng tính dục của bạn khi đối mặt với phụ nữ đã có chồng sẽ tăng gấp bội. (Mị lực đặc biệt)' },
    { id: 'Thuần Ái Chi Căn', name: 'Thuần Ái Chi Căn', author: 'Mộng Tinh', series: '', cost: 10, quality: 'Trung phẩm', description: 'Nữ giới từng giao hợp với bạn tất nhiên sẽ tìm được người định mệnh của mình, nhưng họ cũng sẽ sinh ra ỷ lại và nghiện Thuần Ái Chi Căn của bạn. (Mị lực đặc biệt)' },
    { id: 'Hùng Tính Lãnh Tụ', name: 'Hùng Tính Lãnh Tụ', author: 'Mộng Tinh', series: '', cost: 20, quality: 'Thượng phẩm', description: 'Bạn tỏa ra hơi thở giống đực cực độ vượng thịnh, sinh linh giống cái trước mặt bạn sẽ không kìm được mà bủn rủn chân tay, và sinh ra dục vọng thần phục. (Mị lực đặc biệt)' },
    { id: 'Hoàng Kim Trải Nghiệm Trấn Hồn Khúc', name: 'Hoàng Kim Trải Nghiệm Trấn Hồn Khúc', author: 'Mộng Tinh', series: '', cost: 50, quality: 'Thần phẩm', description: 'Khi chịu đòn tấn công chí mạng, bạn có thể tua ngược đòn tấn công này cùng thời gian, bạn và đối thủ sẽ không ngừng lặp lại quá trình này, cho đến khi phán định thành công hoặc đối phương từ bỏ tấn công. (Năng lực phòng ngự đặc biệt)' },
    { id: 'Cưỡng Chế Cao Trào', name: 'Cưỡng Chế Cao Trào', author: 'Mộng Tinh', series: '', cost: 25, quality: 'Thượng phẩm', description: 'Bạn sở hữu năng lực độc đáo kiểm soát khoái cảm tình dục của nữ giới. Giai đoạn đầu cần tiếp xúc cơ thể, về sau thậm chí có thể thông qua ánh mắt khiến đối phương cao trào. (Năng lực đặc biệt)' },
    { id: 'Tất Nhiên Bị Nhục', name: 'Tất Nhiên Bị Nhục', author: 'Mộng Tinh', series: '', cost: 0, quality: 'Hạ phẩm', description: 'Bạn tất nhiên sẽ bị người khác giới bên cạnh xâm phạm vì đủ loại tai nạn ngoài ý muốn, cho dù bọn họ không phải xuất phát từ bản ý. (Khí vận -50)' },
    { id: 'Hệ Thống Điều Chế Thế Giới', name: 'Hệ Thống Điều Chế Thế Giới', author: 'Mộng Tinh', series: '', cost: 50, quality: 'Thần phẩm', description: 'Có thể điều khiển quy tắc hành vi của tất cả mọi người trong khu vực, hiệu quả và phạm vi tùy thuộc vào tu vi. (Thần hải +500, Đạo tâm +500)' },
    { id: 'Thiên Sát Cô Tinh', name: 'Thiên Sát Cô Tinh', author: 'Mộng Tinh', series: '', cost: 0, quality: 'Tiên phẩm', description: 'Bạn sinh ra mệnh phạm Tham Lang, khí cô sát ăn mòn xương cốt bám vào linh hồn. Chúng sinh thấy bạn như thấy tai tinh giáng thế, cỏ cây khô héo chim thú kinh sợ bỏ chạy, tình cảm nhân gian vĩnh viễn vô duyên với bạn.\nNhưng thiên đạo đoạt đi thất tình của bạn, cũng ban cho bạn sức mạnh thí thần — binh đao hướng tới tất nhuộm huyết quang, sơ hở của vạn pháp chư thiên trong mắt bạn hiện rõ mồn một. (Khí vận -50, Đạo tâm +250, Pháp lực +250)' },
    { id: 'Mộng Cảnh Trung Nhân', name: 'Mộng Cảnh Trung Nhân', author: 'Mộng Tinh', series: '', cost: 20, quality: 'Thượng phẩm', description: 'Ai ai cũng dường như đã gặp bạn trong mơ, bất kể ngoại mạo bạn thế nào khởi đầu nhất định 100 độ hảo cảm. (Khí vận +50)' },
    { id: 'Cyber Linh Căn', name: 'Cyber Linh Căn', author: 'Mộng Tinh', series: '', cost: 40, quality: 'Thiên phẩm', description: 'Tử phủ của bạn khảm nạm kết đan nano, mỗi ngày có thể tự động thôi diễn công pháp và tu luyện. (Thần hải +150, Tốc độ tu luyện tăng)' },
    { id: 'Vô Hạn Kiếm Chế', name: 'Vô Hạn Kiếm Chế', author: 'Mộng Tinh', series: '', cost: 35, quality: 'Thiên phẩm', description: 'Thân là một luyện khí sư, nắm giữ năng lực giải tích đối với pháp bảo vũ khí, sau khi đạt được một môn công pháp thượng cổ, có thể dùng linh lực trong thời gian ngắn chiếu xạ vũ khí đã được giải tích ra hiện thực, theo tu vi không ngừng tăng lên, có thể chế tạo ra Kiếm Giới được tạo thành từ những vũ khí đã giải tích để đối địch ưu thế. (Thần hải +100, Pháp lực +100)' },
    { id: 'Cảm Đồng Thân Thụ', name: 'Cảm Đồng Thân Thụ', author: 'Mộng Tinh', series: '', cost: 15, quality: 'Trung phẩm', description: 'Bạn có thể thiết lập kênh cảm quan đồng thời với một người, hai người chia sẻ cảm quan và tình cảm với nhau. (Thần hải +25)' },
    { id: 'Nguyệt Định Tình Duyên', name: 'Nguyệt Định Tình Duyên', author: 'Mộng Tinh', series: '', cost: 10, quality: 'Trung phẩm', description: 'Bạn mở đầu tự mang một tình duyên, đầu mỗi tháng tiến hành một lần phán định thuộc tính ngẫu nhiên, dựa trên kết quả phán định để sửa đổi thân phận, cảnh giới của tình duyên bạn (tên họ, ký ức về bạn của tình duyên không đổi) (Phán định Pháp lực quyết định cảnh giới của người đó so với bạn cao hay thấp; phán định Thần hải quyết định thân phận người đó so với bạn cao hay thấp; phán định Đạo tâm quyết định độ hảo cảm của người đó với bạn cao thấp; phán định Không tốc quyết định khoảng cách giữa người đó và bạn xa gần). (Khí vận +20)' },
    { id: 'Ta Thật Sự Không Phân Biệt Được A', name: 'Ta Thật Sự Không Phân Biệt Được A', author: 'Mộng Tinh', series: '', cost: 25, quality: 'Thượng phẩm', description: 'Trong tử phủ của bạn có ba đạo thi thần cuộn mình, mỗi trảm một thi liền phá một tầng gông xiềng thiên mệnh. Chỉ là sự điên cuồng khi thi trùng gặm nhấm đạo cơ, thường khiến bạn không phân biệt được người ngộ đạo là bạn hay là chúng. (Đạo tâm -20, Thần hải +70)' },
    { id: 'Thường Thức Cải Biến', name: 'Thường Thức Cải Biến', author: 'Mộng Tinh', series: '', cost: 50, quality: 'Thần phẩm', description: 'Bạn có thể dùng tứ duy nhất định hoặc cái giá nào đó để định ra một hoặc vài quy tắc hoặc thường thức, mọi người đều cho rằng đó là lẽ đương nhiên và sẽ tuân thủ. (Thần hải +1000)' },
    { id: 'Thiên Mệnh Phản Phái', name: 'Thiên Mệnh Phản Phái', author: 'Tiểu nhân', series: '', cost: 70, quality: 'Thiên phẩm', description: 'Túc mệnh tương khắc, chuyên cướp đoạt cơ duyên của Thiên Mệnh Chi Tử. (Đạo tâm +80, Khí vận +40, Mị lực -10)', },
