    { id: 'Thi Đạo Tông Sư', name: 'Thi Đạo Tông Sư', author: 'Tiểu nhân', series: '', cost: 60, quality: 'Cực phẩm', description: 'Thân hòa tử khí, thi khôi vượt cấp. (Thần hải +40, Pháp lực +40, Đạo tâm +20)', },
