    { id: 'Thâm Lam Gia Điểm', name: 'Thâm Lam Gia Điểm', author: 'Tiểu nhân', series: '', cost: 90, quality: 'Tiên phẩm', description: 'Gia điểm vô hạn, công pháp viên mãn. (Ngộ tính +200, Đạo tâm +100)', },
