    { id: 'Thu Đồ Vạn Bội Phản Hoàn', name: 'Thu Đồ Vạn Bội Phản Hoàn', author: 'Tiểu nhân', series: '', cost: 90, quality: 'Tiên phẩm', description: 'Ban cơ duyên cho đồ đệ nhận phản hoàn. (Khí vận +150, Mị lực +50)', },
