    { id: 'Tông Sư Điều Giáo', name: 'Tông Sư Điều Giáo', author: 'Tiểu nhân', series: '', cost: 10, quality: 'Phàm phẩm', description: 'Tinh thông roi da, nến, mộc mã. Điều giáo nữ tu trinh liệt thành chó cái nghe lời, lấy việc lộ đuôi và đeo vòng cổ làm vinh dự.', },
    { id: 'Cải Tạo Cơ Thể', name: 'Cải Tạo Cơ Thể', author: 'Tiểu nhân', series: '', cost: 10, quality: 'Phàm phẩm', description: 'Tinh thông thuật cải tạo máu thịt. Tùy ý điều chỉnh vóc dáng, nâng ngực độn mông, biến nữ tu thành cỗ máy tình dục hoàn hảo.', },
    { id: 'Tẩy Não Bằng Tinh Dịch', name: 'Tẩy Não Bằng Tinh Dịch', author: 'Tiểu nhân', series: '', cost: 10, quality: 'Phàm phẩm', description: 'Tinh dịch mang theo ý chí. Xuất trong càng nhiều, tư tưởng nữ tu càng bị đồng hóa, cuối cùng biến thành con rối sống vì ngươi.', },
    { id: 'Cướp Đoạt Trinh Tiết', name: 'Cướp Đoạt Trinh Tiết', author: 'Tiểu nhân', series: '', cost: 10, quality: 'Phàm phẩm', description: 'Cướp lần đầu nhận thưởng bạo kích. Nhiệt tình thu thập lạc hồng của Tiên tử, Thánh nữ, treo ga giường nhuốm máu làm chiến lợi phẩm.', },
    { id: 'Hiển Thị Độ Hảo Cảm', name: 'Hiển Thị Độ Hảo Cảm', author: 'Tiểu nhân', series: '', cost: 10, quality: 'Phàm phẩm', description: 'Nhìn thấy độ hảo cảm và chỉ số dục vọng. Thông qua lựa chọn chính xác nhanh chóng cày max hảo cảm, mở khóa tư thế khó.', },
    { id: 'Cự Mãng Dưới Háng', name: 'Cự Mãng Dưới Háng', author: 'Tiểu nhân', series: '', cost: 10, quality: 'Phàm phẩm', description: 'Kích thước dương vật kinh người. Cương cứng như mãng xà xuất động, đâm thẳng hoàng long, cho nữ tu trải nghiệm khoái cảm như sắp chết.', },
    { id: 'Trừng Phạt Chiến Bại', name: 'Trừng Phạt Chiến Bại', author: 'Tiểu nhân', series: '', cost: 10, quality: 'Phàm phẩm', description: 'Nữ tu bị đánh bại sẽ cưỡng chế phát tình. Phải giao hợp ngay tại chiến trường mới giải trừ, nếu không sẽ bạo thể.', },
    { id: 'Ký Sinh Xúc Tu', name: 'Ký Sinh Xúc Tu', author: 'Tiểu nhân', series: '', cost: 10, quality: 'Phàm phẩm', description: 'Gieo hạt giống xúc tu vào nữ tu. Xúc tu tự động điều giáo vật chủ khi ngươi vắng mặt, ngăn chặn ngoại tình.', },

    // --- PHÀM PHẨM ---
    { id: 'Kim Linh Căn', name: 'Kim Linh Căn', author: 'Thiên Ngỗng Phi Tiên', series: '', cost: 5, quality: 'Phàm phẩm', description: 'Cảm ứng cơ bản với nguyên tố Kim. Hấp thu linh khí chuyển hóa thành Kim Linh Lực thô sơ.\n- [Tu Luyện]: Tốc độ hấp thu trung bình, tốn thời gian lọc tạp chất.\n- [Cộng Hưởng]: Cầm vũ khí kim loại đầm tay hơn, tăng nhẹ độ sắc bén. (Thần hải +2, Pháp lực +1)', },
    { id: 'Mộc Linh Căn', name: 'Mộc Linh Căn', author: 'Thiên Ngỗng Phi Tiên', series: '', cost: 5, quality: 'Phàm phẩm', description: 'Tư chất mộc hệ nhập môn. Hấp thu linh khí chuyển hóa thành Mộc Linh Lực nuôi dưỡng cơ thể.\n- [Dưỡng Sinh]: Thích hợp công pháp dưỡng sinh, tiến cảnh chậm nhưng ít tâm ma.\n- [Hồi Phục]: Vết thương ngoài da lành nhanh hơn 10%. (Thần hải +2, Pháp lực +1)', },
    { id: 'Thủy Linh Căn', name: 'Thủy Linh Căn', author: 'Thiên Ngỗng Phi Tiên', series: '', cost: 5, quality: 'Phàm phẩm', description: 'Cảm ứng thủy khí như ao hồ. Hấp thu linh khí chuyển hóa thành Thủy Linh Lực nhu hòa.\n- [Tĩnh Tâm]: Duy trì thiền định tốt, giảm tiêu hao tinh thần khi bế quan.\n- [Thủy Tính]: Nhịn thở dưới nước lâu hơn 15 phút. (Pháp lực +2, Thần hải +1)', },
    { id: 'Hỏa Linh Căn', name: 'Hỏa Linh Căn', author: 'Thiên Ngỗng Phi Tiên', series: '', cost: 5, quality: 'Phàm phẩm', description: 'Cảm nhận nhiệt lượng yếu ớt. Hấp thu linh khí chuyển hóa thành Hỏa Linh Lực nóng bỏng.\n- [Ưa Nhiệt]: Tu luyện tốt nơi khô nóng, giảm tốc độ nơi ẩm ướt.\n- [Kháng Nóng]: Chịu được nắng gắt, khó bị say nắng. (Pháp lực +2, Thần hải +1)', },
    { id: 'Thổ Linh Căn', name: 'Thổ Linh Căn', author: 'Thiên Ngỗng Phi Tiên', series: '', cost: 5, quality: 'Phàm phẩm', description: 'Tư chất đất ruộng thông thường. Hấp thu linh khí chuyển hóa thành Thổ Linh Lực trầm ổn.\n- [Định Tâm]: Khó bị ngoại cảnh làm phân tâm, giảm rủi ro tẩu hỏa.\n- [Da Dày]: Da thịt cứng hơn người thường, chịu đòn tốt hơn. (Đạo tâm +2, Pháp lực +1)', },
    { id: 'Phong Linh Căn', name: 'Phong Linh Căn', author: 'Thiên Ngỗng Phi Tiên', series: '', cost: 5, quality: 'Phàm phẩm', description: 'Cảm ứng yếu ớt với luồng khí lưu chuyển. Hấp thu linh khí trời đất chuyển hóa thành Phong Linh Lực nhẹ nhàng.\n- [Chuyển Hóa]: Phong Linh Lực giúp thân thủ nhanh hơn 5% tốc độ cơ bản.\n- [Khinh Thân]: Nhảy cao hơn một chút, giảm nhẹ sát thương khi rơi từ trên cao. (Pháp lực +2, Thần hải +1)', },
    { id: 'Lôi Linh Căn', name: 'Lôi Linh Căn', author: 'Thiên Ngỗng Phi Tiên', series: '', cost: 5, quality: 'Phàm phẩm', description: 'Linh lực mang theo điện tích. Hấp thu linh khí trong khí quyển chuyển hóa thành Lôi Linh Lực bạo liệt.\n- [Chuyển Hóa]: Lôi Linh Lực khiến đòn đánh có xác suất nhỏ làm tê liệt đối thủ trong tích tắc.\n- [Nhạy Bén]: Phản ứng trước nguy hiểm nhanh hơn nhờ xung điện thần kinh. (Thần hải +2, Pháp lực +1)', },
    { id: 'Băng Linh Căn', name: 'Băng Linh Căn', author: 'Thiên Ngỗng Phi Tiên', series: '', cost: 5, quality: 'Phàm phẩm', description: 'Biến thể lạnh lẽo của Thủy hệ. Hấp thu linh khí môi trường chuyển hóa thành Băng Linh Lực giá buốt.\n- [Chuyển Hóa]: Băng Linh Lực bao phủ chiêu thức làm chậm nhẹ tốc độ ra chiêu đối phương.\n- [Kháng Lạnh]: Giữ nhiệt độ cơ thể ổn định trong môi trường giá rét thông thường. (Pháp lực +2, Đạo tâm +1)', },
    { id: 'Quang Linh Căn', name: 'Quang Linh Căn', author: 'Thiên Ngỗng Phi Tiên', series: '', cost: 5, quality: 'Phàm phẩm', description: 'Cảm ứng với quang năng. Hấp thu linh khí từ ánh sáng chuyển hóa thành Quang Linh Lực thuần khiết.\n- [Chuyển Hóa]: Quang Linh Lực giúp hồi phục sinh lực nhanh hơn một chút khi đứng dưới ánh nắng.\n- [Thị Giác]: Nhìn rõ hơn trong môi trường thiếu sáng hoặc sương mù dày đặc. (Thần hải +2, Pháp lực +1)', },
    { id: 'Ám Linh Căn', name: 'Ám Linh Căn', author: 'Thiên Ngỗng Phi Tiên', series: '', cost: 5, quality: 'Phàm phẩm', description: 'Thích ứng với bóng tối. Hấp thu linh khí từ âm ảnh chuyển hóa thành Ám Linh Lực thâm trầm.\n- [Chuyển Hóa]: Ám Linh Lực giúp hơi thở dễ dàng hòa lẫn vào bóng tối, khó bị phát hiện.\n- [Dạ Nhãn]: Có thể nhìn thấy lờ mờ các vật thể trong bóng tối hoàn toàn. (Pháp lực +2, Thần hải +1)', },
    { id: 'Không Linh Căn', name: 'Không Linh Căn', author: 'Thiên Ngỗng Phi Tiên', series: '', cost: 8, quality: 'Phàm phẩm', description: 'Cảm ứng với vết nứt không gian li ti. Hấp thu linh khí từ hư không chuyển hóa thành Không Linh Lực hư ảo.\n- [Chuyển Hóa]: Không Linh Lực làm mờ thực thể, có xác suất nhỏ né tránh các đòn tầm xa.\n- [Trữ Vật]: Không gian đan điền mở rộng giúp rương đồ có thêm 5 ô chứa. (Thần hải +3)', },
    { id: 'Thời Linh Căn', name: 'Thời Linh Căn', author: 'Thiên Ngỗng Phi Tiên', series: '', cost: 8, quality: 'Phàm phẩm', description: 'Cảm nhận sự trôi qua của thời gian. Hấp thu linh khí thời gian chuyển hóa thành Thời Linh Lực ổn định.\n- [Chuyển Hóa]: Thời Linh Lực giúp cảm nhận nhịp độ trận đấu chậm lại, tăng khả năng phản xạ.\n- [Tập Trung]: Lĩnh ngộ kỹ năng nhanh hơn 5% do nhận thức thời gian khác biệt. (Đạo tâm +3)', },

                // --- HẠ PHẨM ---
                { id: 'Thiết Tinh Linh Căn', name: 'Thiết Tinh Linh Căn', author: 'Thiên Ngỗng Phi Tiên', series: '', cost: 10, quality: 'Hạ phẩm', description: 'Linh căn ngưng tụ tinh hoa sắt thép. Hấp thu linh khí hoặc tinh túy kim loại chuyển hóa thành Thiết Tinh Linh Lực sắc bén.\n- [Cường Hóa]: Tăng 10% độ bền và sắc bén cho vũ khí kim loại.\n- [Vết Thương Sâu]: Pháp thuật gây hiệu ứng "Chảy Máu" nhẹ. (Thần hải +6, Pháp lực +3)', },
                { id: 'Thanh Đằng Linh Căn', name: 'Thanh Đằng Linh Căn', author: 'Thiên Ngỗng Phi Tiên', series: '', cost: 10, quality: 'Hạ phẩm', description: 'Hình thái dây mây dẻo dai. Hấp thu linh khí mộc diệp chuyển hóa thành Thanh Đằng Linh Lực tràn đầy sinh cơ.\n- [Trói Buộc]: Pháp thuật khống chế bền hơn 20%, khó bị giật đứt.\n- [Hấp Thu]: Đứng trên đất cỏ hồi máu nhanh gấp đôi. (Thần hải +5, Pháp lực +4)', },
                { id: 'Vụ Thủy Linh Căn', name: 'Vụ Thủy Linh Căn', author: 'Thiên Ngỗng Phi Tiên', series: '', cost: 10, quality: 'Hạ phẩm', description: 'Thủy khí hóa sương mù lãng đãng. Hấp thu linh khí hơi nước chuyển hóa thành Vụ Thủy Linh Lực hư ảo.\n- [Màn Sương]: Pháp thuật tỏa hơi nước làm giảm chính xác của địch.\n- [Thẩm Thấu]: Linh lực xâm nhập qua lỗ chân lông gây hiệu ứng "Ẩm Ướt". (Pháp lực +5, Thần hải +4)', },
                { id: 'Xích Hỏa Linh Căn', name: 'Xích Hỏa Linh Căn', author: 'Thiên Ngỗng Phi Tiên', series: '', cost: 10, quality: 'Hạ phẩm', description: 'Lửa đỏ ổn định như than hồng. Hấp thu linh khí hỏa diệm chuyển hóa thành Xích Hỏa Linh Lực rực rỡ.\n- [Khống Hỏa]: Giảm 10% tỷ lệ nổ lò khi luyện đan nhờ lửa ổn định.\n- [Hộ Thể]: Giảm 20% sát thương từ pháp thuật Băng/Hàn cấp thấp. (Pháp lực +6, Thần hải +3)', },
                { id: 'Thanh Thạch Linh Căn', name: 'Thanh Thạch Linh Căn', author: 'Thiên Ngỗng Phi Tiên', series: '', cost: 10, quality: 'Hạ phẩm', description: 'Cứng cỏi như đá xanh. Hấp thu linh khí thổ thạch chuyển hóa thành Thanh Thạch Linh Lực nặng nề.\n- [Nham Giáp]: Kích hoạt lớp bảo hộ giảm 5% mọi sát thương vật lý.\n- [Kiên Định]: Kháng các loại mê hoặc tâm trí cấp thấp. (Đạo tâm +5, Thần hải +4)', },
                { id: 'Tật Phong Linh Căn', name: 'Tật Phong Linh Căn', author: 'Thiên Ngỗng Phi Tiên', series: '', cost: 10, quality: 'Hạ phẩm', description: 'Gió đã bắt đầu kết tụ thành hình thái rõ rệt. Hấp thu linh khí chuyển hóa thành Tật Phong Linh Lực vận hành cực nhanh.\n- [Chuyển Hóa]: Linh lực bọc quanh chân giúp lướt ngắn né chiêu mà không tốn thể lực.\n- [Cắt Gió]: Pháp thuật Phong hệ gây thêm sát thương cắt sâu vào da thịt đối phương. (Thần hải +5, Pháp lực +5)', },
                { id: 'U Lôi Linh Căn', name: 'U Lôi Linh Căn', author: 'Thiên Ngỗng Phi Tiên', series: '', cost: 10, quality: 'Hạ phẩm', description: 'Lôi điện mang màu tím u tối. Hấp thu linh khí sấm sét chuyển hóa thành U Lôi Linh Lực có tính dẫn truyền.\n- [Chuyển Hóa]: Linh lực bùng nổ khi chạm mục tiêu, có xác suất gây choáng trong 1 giây.\n- [Dẫn Điện]: Sát thương lôi điện có thể lan sang các mục tiêu đứng sát cạnh nhau. (Thần hải +7, Pháp lực +3)', },
                { id: 'Hàn Băng Linh Căn', name: 'Hàn Băng Linh Căn', author: 'Thiên Ngỗng Phi Tiên', series: '', cost: 10, quality: 'Hạ phẩm', description: 'Hàn khí tích tụ thành băng tinh. Hấp thu linh khí từ băng giá chuyển hóa thành Hàn Băng Linh Lực lạnh thấu xương.\n- [Chuyển Hóa]: Giảm 20% tốc độ di chuyển của mục tiêu khi bị trúng linh lực băng.\n- [Băng Giáp]: Tạo lớp màng băng mỏng giảm 5% sát thương vật lý nhận vào. (Pháp lực +6, Thần hải +4)', },
                { id: 'Thánh Quang Linh Căn', name: 'Thánh Quang Linh Căn', author: 'Thiên Ngỗng Phi Tiên', series: '', cost: 10, quality: 'Hạ phẩm', description: 'Ánh sáng mang hơi ấm chữa lành. Hấp thu linh khí quang minh chuyển hóa thành Thánh Quang Linh Lực xua tan tiêu cực.\n- [Chuyển Hóa]: Linh lực này giúp giảm thời gian chịu ảnh hưởng của các hiệu ứng suy yếu.\n- [Hào Quang]: Tỏa sáng trong bán kính 5 mét, gây khó chịu cho sinh vật tà ác. (Thần hải +7, Pháp lực +3)', },
                { id: 'U Ám Linh Căn', name: 'U Ám Linh Căn', author: 'Thiên Ngỗng Phi Tiên', series: '', cost: 10, quality: 'Hạ phẩm', description: 'Linh lực như mực đen, hòa tan vào bóng tối. Hấp thu linh khí hắc ám chuyển hóa thành U Ám Linh Lực ẩn mật.\n- [Chuyển Hóa]: Tăng 15% sát thương khi tấn công từ phía sau hoặc từ trong bóng tối.\n- [Hút Hồn]: Gây sát thương có xác suất nhỏ hồi phục 1% mana bản thân. (Pháp lực +6, Thần hải +4)', },
                { id: 'Hư Không Linh Căn', name: 'Hư Không Linh Căn', author: 'Thiên Ngỗng Phi Tiên', series: '', cost: 15, quality: 'Hạ phẩm', description: 'Cảm nhận các tầng không gian chồng lấp. Hấp thu linh khí từ hư vô chuyển hóa thành Hư Không Linh Lực mờ ảo.\n- [Xuyên Thấu]: Linh lực giúp bản thân có thể đi xuyên qua các vật thể mỏng hoặc cửa gỗ.\n- [Hư Bộ]: Tăng khả năng né tránh các đòn đánh vật lý cơ bản thêm 10%. (Thần hải +10)', },
                { id: 'Niên Luân Linh Căn', name: 'Niên Luân Linh Căn', author: 'Thiên Ngỗng Phi Tiên', series: '', cost: 15, quality: 'Hạ phẩm', description: 'Linh lực vận hành theo chu kỳ vòng đời. Hấp thu linh khí thời gian chuyển hóa thành Niên Luân Linh Lực ổn định.\n- [Duy Trì]: Các hiệu ứng hỗ trợ của bản thân tồn tại lâu hơn 10% thời gian gốc.\n- [Trì Hoãn]: Giảm tốc độ tiêu hao thể lực khi chiến đấu liên tục trong thời gian dài. (Đạo tâm +10)', },

                // --- TRUNG PHẨM ---
                { id: 'Huyền Thiết Linh Căn', name: 'Huyền Thiết Linh Căn', author: 'Thiên Ngỗng Phi Tiên', series: '', cost: 15, quality: 'Trung phẩm', description: 'Linh căn Huyền Thiết ngàn năm. Hấp thu linh khí hoặc huyền thiết khoáng chuyển hóa thành Huyền Thiết Linh Lực sát phạt.\n- [Phá Giáp]: Đòn tấn công bỏ qua 15% phòng thủ vật lý đối phương.\n- [Kiếm Khí]: Có 20% xác suất phóng kiếm khí gây sát thương chuẩn. (Thần hải +12, Pháp lực +8)', },
                { id: 'Bách Thảo Linh Căn', name: 'Bách Thảo Linh Căn', author: 'Thiên Ngỗng Phi Tiên', series: '', cost: 15, quality: 'Trung phẩm', description: 'Đan điền như vườn dược thảo. Hấp thu linh khí bách thảo chuyển hóa thành Bách Thảo Linh Lực thanh lọc cơ thể.\n- [Dược Thân]: Hiệu quả đan dược tăng 30%, tự động bài tiết đan độc.\n- [Thúc Sinh]: Dùng linh lực giảm 10% thời gian trưởng thành linh thảo. (Thần hải +12, Pháp lực +8)', },
                { id: 'Lưu Thủy Linh Căn', name: 'Lưu Thủy Linh Căn', author: 'Thiên Ngỗng Phi Tiên', series: '', cost: 15, quality: 'Trung phẩm', description: 'Pháp lực cuộn trào như dòng xiết. Hấp thu linh khí giang hồ chuyển hóa thành Lưu Thủy Linh Lực miên man không dứt.\n- [Bất Tận]: Hồi phục mana tăng 50% khi ở gần nguồn nước lớn.\n- [Linh Động]: Di chuyển để lại tàn ảnh nước, tăng khả năng né tránh. (Pháp lực +10, Thần hải +10)', },
                { id: 'Liệt Hỏa Linh Căn', name: 'Liệt Hỏa Linh Căn', author: 'Thiên Ngỗng Phi Tiên', series: '', cost: 15, quality: 'Trung phẩm', description: 'Lửa cháy hung tàn. Hấp thu linh khí liệt diễm chuyển hóa thành Liệt Hỏa Linh Lực bùng nổ mạnh mẽ.\n- [Thiêu Đốt]: Đòn đánh gây "Bỏng nặng", rút máu 5 hiệp liên tục.\n- [Cuồng Nộ]: Khi mana dưới 30%, sát thương Hỏa tăng đột biến 50%. (Pháp lực +12, Thần hải +8)', },
                { id: 'Nham Thạch Linh Căn', name: 'Nham Thạch Linh Căn', author: 'Thiên Ngỗng Phi Tiên', series: '', cost: 15, quality: 'Trung phẩm', description: 'Vững như núi đá. Hấp thu linh khí nham thạch chuyển hóa thành Nham Thạch Linh Lực vững chãi như bàn thạch.\n- [Bất Động]: Đứng yên tăng gấp đôi thủ vật lý, miễn nhiễm đẩy lùi.\n- [Địa Chấn]: Đòn đánh mạnh gây chấn động làm choáng kẻ địch gần. (Đạo tâm +12, Pháp lực +8)', },
                { id: 'Cuồng Phong Linh Căn', name: 'Cuồng Phong Linh Căn', author: 'Thiên Ngỗng Phi Tiên', series: '', cost: 15, quality: 'Trung phẩm', description: 'Gió gào thét trong đan điền. Hấp thu linh khí bão tố chuyển hóa thành Cuồng Phong Linh Lực mạnh mẽ.\n- [Chuyển Hóa]: Cho phép lướt nhanh bỏ qua vật cản, tạo áp suất gió làm chậm kẻ địch xung quanh.\n- [Cắt Nát]: Tăng mạnh sát thương của các pháp thuật gió mang tính cắt gọt vật chất. (Thần hải +12, Pháp lực +8)', },
                { id: 'Thiên Lôi Linh Căn', name: 'Thiên Lôi Linh Căn', author: 'Thiên Ngỗng Phi Tiên', series: '', cost: 15, quality: 'Trung phẩm', description: 'Linh lực mang uy nghiêm của sấm sét. Hấp thu linh khí lôi đình chuyển hóa thành Thiên Lôi Linh Lực chấn động.\n- [Chuyển Hóa]: Đòn đánh có 15% xác suất gây tê liệt hoàn toàn đối thủ trong 2 giây.\n- [Bạo Phát]: Tăng tốc độ xuất chiêu 30% và gây sát thương bùng nổ cuối chuỗi chiêu. (Thần hải +15, Pháp lực +5)', },
                { id: 'Huyền Băng Linh Căn', name: 'Huyền Băng Linh Căn', author: 'Thiên Ngỗng Phi Tiên', series: '', cost: 15, quality: 'Trung phẩm', description: 'Băng đen lạnh thấu xương tủy. Hấp thu linh khí cực hàn chuyển hóa thành Huyền Băng Linh Lực đóng băng.\n- [Chuyển Hóa]: Linh lực có tính đông kết cao, phản lại 10% sát thương cận chiến bằng băng gai.\n- [Tĩnh Lặng]: Giảm 15% tiêu hao mana khi chiến đấu trong môi trường lạnh giá. (Pháp lực +12, Thần hải +8)', },
                { id: 'Diệu Quang Linh Căn', name: 'Diệu Quang Linh Căn', author: 'Thiên Ngỗng Phi Tiên', series: '', cost: 15, quality: 'Trung phẩm', description: 'Ánh sáng rực rỡ chói lòa. Hấp thu linh khí quang huy chuyển hóa thành Diệu Quang Linh Lực thánh khiết.\n- [Chuyển Hóa]: Linh lực giúp gia tăng 25% hiệu quả trị liệu và tạo giáp ánh sáng bảo vệ.\n- [Vô Ảnh]: Tăng tốc độ phản xạ và né tránh đáng kể khi đứng ở nơi có ánh sáng mạnh. (Thần hải +15, Pháp lực +5)', },
                { id: 'Ma Ám Linh Căn', name: 'Ma Ám Linh Căn', author: 'Thiên Ngỗng Phi Tiên', series: '', cost: 15, quality: 'Trung phẩm', description: 'Bóng tối đen đặc như mực. Hấp thu linh khí hắc hỏa chuyển hóa thành Ma Ám Linh Lực thôn phệ.\n- [Chuyển Hóa]: Hồi phục 5% mana khi tiêu diệt mục tiêu. Đòn đánh có xác suất gây hoảng sợ.\n- [Ám Vực]: Tạo vùng tối bao quanh bản thân khiến địch bị giảm tầm nhìn xuống tối thiểu. (Pháp lực +15, Thần hải +5)', },
                { id: 'Di Động Linh Căn', name: 'Di Động Linh Căn', author: 'Thiên Ngỗng Phi Tiên', series: '', cost: 20, quality: 'Trung phẩm', description: 'Can thiệp vào không gian vật chất. Hấp thu linh khí không gian chuyển hóa thành Di Động Linh Lực dịch chuyển.\n- [Chuyển Hóa]: Linh lực cho phép dịch chuyển tức thời vị trí trong tầm mắt ở khoảng cách ngắn.\n- [Gấp Khúc]: Tăng tầm xa của các pháp thuật thêm 30% bằng cách bẻ cong không gian. (Thần hải +20)', },
                { id: 'Trệ Thời Linh Căn', name: 'Trệ Thời Linh Căn', author: 'Thiên Ngỗng Phi Tiên', series: '', cost: 20, quality: 'Trung phẩm', description: 'Tạo ra vùng thời gian trôi chậm. Hấp thu linh khí thời gian chuyển hóa thành Trệ Thời Linh Lực ngưng đọng.\n- [Chuyển Hóa]: Linh lực làm chậm thời gian của mục tiêu bị trúng chiêu trong vòng 3 giây.\n- [Hồi Tưởng]: Có 10% xác suất hồi lại kỹ năng vừa sử dụng ngay lập tức mà không cần chờ. (Đạo tâm +20)', },

                // --- THƯỢNG PHẨM ---
                { id: 'Thái Bạch Linh Căn', name: 'Thái Bạch Linh Căn', author: 'Thiên Ngỗng Phi Tiên', series: '', cost: 25, quality: 'Thượng phẩm', description: 'Sát khí sao Thái Bạch. Hấp thu linh khí tinh tú phương Tây chuyển hóa thành Thái Bạch Linh Lực vô kiên bất tồi.\n- [Kiếm Tâm]: Lĩnh ngộ Kiếm Ý nhanh gấp 5 lần người thường.\n- [Xuyên Thấu]: Đòn đánh bỏ qua 30% giáp và hộ thể khí tráo. (Thần hải +30, Pháp lực +20)', },
                { id: 'Trường Sinh Linh Căn', name: 'Trường Sinh Linh Căn', author: 'Thiên Ngỗng Phi Tiên', series: '', cost: 25, quality: 'Thượng phẩm', description: 'Sinh cơ cổ mộc ngàn năm. Hấp thu linh khí trường sinh chuyển hóa thành Trường Sinh Linh Lực bất hủ.\n- [Bất Tử]: Tự hồi 5% máu mỗi hiệp. Miễn nhiễm hầu hết kịch độc.\n- [Chuyển Hóa]: Hy sinh tuổi thọ để bùng nổ sức mạnh khi nguy cấp. (Thần hải +30, Pháp lực +20)', },
                { id: 'Huyền Thủy Linh Căn', name: 'Huyền Thủy Linh Căn', author: 'Thiên Ngỗng Phi Tiên', series: '', cost: 25, quality: 'Thượng phẩm', description: 'Nước nơi đáy vực thẳm. Hấp thu linh khí u minh thủy chuyển hóa thành Huyền Thủy Linh Lực thâm trầm lạnh lẽo.\n- [Áp Bách]: Giảm 30% tốc độ di chuyển và 20% tốc độ đánh của địch.\n- [Thôn Phệ]: Hấp thu một phần mana từ đòn phép của đối phương. (Pháp lực +25, Thần hải +25)', },
                { id: 'Tử Dương Linh Căn', name: 'Tử Dương Linh Căn', author: 'Thiên Ngỗng Phi Tiên', series: '', cost: 25, quality: 'Thượng phẩm', description: 'Lửa tím thái dương. Hấp thu linh khí tử vi chuyển hóa thành Tử Dương Linh Lực thanh tẩy tà ma.\n- [Phá Tà]: Gây 200% sát thương lên hệ Ma/Quỷ/Vong Linh.\n- [Luyện Hóa]: Tốc độ luyện đan/hấp thu nhanh gấp 3 lần bình thường. (Pháp lực +30, Thần hải +20)', },
                { id: 'Hậu Thổ Linh Căn', name: 'Hậu Thổ Linh Căn', author: 'Thiên Ngỗng Phi Tiên', series: '', cost: 25, quality: 'Thượng phẩm', description: 'Đức dày chở vật. Hấp thu linh khí địa mạch chuyển hóa thành Hậu Thổ Linh Lực bao dung vạn vật.\n- [Địa Mạch]: Chân chạm đất được hồi mana liên tục từ mạch đất.\n- [Thổ Độn]: Di chuyển ngàn dặm trong lòng đất, xuyên mọi địa hình. (Đạo tâm +30, Pháp lực +20)', },
                { id: 'Ngự Phong Linh Căn', name: 'Ngự Phong Linh Căn', author: 'Thiên Ngỗng Phi Tiên', series: '', cost: 25, quality: 'Thượng phẩm', description: 'Làm chủ gió trời tự tại. Hấp thu linh khí thiên địa chuyển hóa thành Ngự Phong Linh Lực phi hành.\n- [Chuyển Hóa]: Ngự không phi hành tốc độ cao với mana tiêu hao cực thấp. Miễn nhiễm làm chậm.\n- [Phong Sát]: Tạo vòng xoáy linh lực cắt đứt mọi pháp thuật tầm xa hướng về bản thân. (Thần hải +30, Pháp lực +20)', },
