async function populateWorldBookWithDefaults() {
  console.log('Đang sử dụng dữ liệu mặc định để điền vào Sách Thế Giới...');
  const { talents, backgrounds, presets } = DEFAULT_EDITOR_DATA;
  let successCount = 0;
  let failCount = 0;

  const processItems = async (items, type, saveFunction) => {
    for (const item of items) {
      try {
        if (await saveFunction(item, type)) {
          successCount++;
        } else {
          failCount++;
        }
      } catch (e) {
        failCount++;
        console.error(`Lưu mặc định ${type} thất bại: ${item.name}`, e);
      }
    }
  };

  await processItems(talents, 'talent', WorldBookManager.saveTalentOrBackground.bind(WorldBookManager));
  await processItems(backgrounds, 'background', WorldBookManager.saveTalentOrBackground.bind(WorldBookManager));
  await processItems(presets, 'preset', WorldBookManager.savePreset.bind(WorldBookManager));

  if (failCount > 0) {
    await guiXuAlert(`Khởi tạo Sách Thế Giới hoàn thành một phần. Thành công: ${successCount}, Thất bại: ${failCount}. Vui lòng xem chi tiết trong console.`, 'Cảnh báo');
  } else {
    await guiXuAlert(`Khởi tạo Sách Thế Giới thành công, tổng cộng ghi vào ${successCount} mục dữ liệu mặc định.`);
  }
}

async function promptForDefaultImport() {
  return new Promise(resolve => {
    const modal = document.getElementById('default-import-modal');
    const confirmBtn = document.getElementById('import-defaults-confirm-btn');
    const laterBtn = document.getElementById('import-defaults-later-btn');
    modal.style.display = 'flex';
    const onConfirm = async () => {
      modal.style.display = 'none';
      document.getElementById('loading-overlay').style.display = 'flex';
      await populateWorldBookWithDefaults();
      document.getElementById('loading-overlay').style.display = 'none';
      cleanup();
      resolve(true);
    };
    const onLater = () => {
      modal.style.display = 'none';
      cleanup();
      resolve(false);
    };
    const cleanup = () => {
        confirmBtn.removeEventListener('click', onConfirm);
        laterBtn.removeEventListener('click', onLater);
    };
    confirmBtn.addEventListener('click', onConfirm);
    laterBtn.addEventListener('click', onLater);
  });
}

async function loadEditorData() {
  if (editorData.isLoading) return true;
  editorData.isLoading = true;
  document.getElementById('loading-overlay').style.display = 'flex';

  try {
    const loadingPlaceholder = `<div class="loading-placeholder">Đang tải dữ liệu từ Sách Thế Giới...</div>`;
    ['talent-list-container', 'background-list-container', 'preset-list-container', 'worldbook-list-container'].forEach(id => {
        const el = document.getElementById(id);
        if (el) el.innerHTML = loadingPlaceholder;
    });

    console.log('Bắt đầu tải dữ liệu trình chỉnh sửa từ Sách Thế Giới...');
    const worldBookData = await WorldBookManager.loadAllData();

    // **Tối ưu logic**: Chỉ khi Thiên phú và Xuất thân đều trống mới nhắc nhập
    const needsDefaultImport = worldBookData.talents.length === 0 && worldBookData.backgrounds.length === 0;

    if (needsDefaultImport) {
      // Ẩn hoạt ảnh tải để tránh che modal
      document.getElementById('loading-overlay').style.display = 'none';
      const imported = await promptForDefaultImport();
      if (imported) {
        // Hiển thị lại hoạt ảnh tải và tải dữ liệu mới
        document.getElementById('loading-overlay').style.display = 'flex';
        const reloadedData = await WorldBookManager.loadAllData();
        Object.assign(editorData, {
            talents: reloadedData.talents || [],
            backgrounds: reloadedData.backgrounds || [],
            presets: reloadedData.presets || [],
            worldbookEntries: reloadedData.worldbookEntries || [],
        });
      } else {
        Object.assign(editorData, { talents: [], backgrounds: [], presets: [], worldbookEntries: [] });
      }
    } else {
      Object.assign(editorData, {
          talents: worldBookData.talents || [],
          backgrounds: worldBookData.backgrounds || [],
          presets: worldBookData.presets || [],
          worldbookEntries: worldBookData.worldbookEntries || [],
      });
    }

    editorData.lastLoadTime = Date.now();
    console.log(`Tải dữ liệu trình chỉnh sửa hoàn tất: ${editorData.talents.length} Thiên Phú, ${editorData.backgrounds.length} Xuất Thân, ${editorData.presets.length} Khởi Đầu Mẫu, ${editorData.worldbookEntries.length} Thế Giới`);
    renderAllEditors();
    return true;
  } catch (error) {
    console.error('Xảy ra lỗi nghiêm trọng khi tải dữ liệu trình chỉnh sửa:', error);
    await guiXuAlert('Tải dữ liệu trình chỉnh sửa thất bại, vui lòng kiểm tra console.\nLỗi: ' + error.message, 'Lỗi');
    return false;
  } finally {
    editorData.isLoading = false;
    document.getElementById('loading-overlay').style.display = 'none';
  }
}

async function resetEditorToDefaults() {
  const confirmed = await guiXuConfirm('Bạn có chắc chắn muốn đặt lại trình chỉnh sửa không? Thao tác này sẽ xóa tất cả các mục 【Thiên Phú】 và 【Xuất Thân】 trong Sách Thế Giới, và ghi lại dữ liệu mặc định. Thao tác này không thể hoàn tác!', 'Xác nhận đặt lại');
  if (!confirmed) return;

  document.getElementById('loading-overlay').style.display = 'flex';
  try {
    await TavernHelper.updateWorldbookWith(WorldBookManager.LOREBOOK_NAME, (worldbook) => {
        return worldbook.filter(entry => {
            return !entry.name.startsWith('【Thiên Phú】') && !entry.name.startsWith('【Xuất Thân】');
        });
    });
    await populateWorldBookWithDefaults();
    await loadEditorData();
  } catch (error) {
    console.error('Đặt lại trình chỉnh sửa thất bại:', error);
    await guiXuAlert('Đặt lại thất bại, vui lòng xem chi tiết trong console.', 'Lỗi');
  } finally {
    document.getElementById('loading-overlay').style.display = 'none';
  }
}

