let currentWbFilter = 'all';
function renderWorldBookEditor() {
    const container = document.getElementById('worldbook-list-container');
    if (!container) return;

    // UPDATE: Tab count
    const tabBtn = document.querySelector('button[data-tab="worldbooks"]');
    if (tabBtn) tabBtn.innerHTML = `Trình chỉnh sửa Sách Thế Giới (${editorData.worldbookEntries.length})`;

    // UPDATE: Filter counts
    const counts = {
        all: editorData.worldbookEntries.length,
        general: 0,
        preset: 0,
        talent: 0,
        background: 0
    };

    editorData.worldbookEntries.forEach(entry => {
        const name = entry.name.trim();
        if (name.startsWith('【Thế Giới】') || name.includes('【Thế Giới】')) counts.general++;
        else if (name.startsWith('【Khởi Đầu Mẫu】') || name.includes('【Khởi Đầu Mẫu】')) counts.preset++;
        else if (name.startsWith('【Thiên Phú】') || name.includes('【Thiên Phú】')) counts.talent++;
        else if (name.startsWith('【Xuất Thân】') || name.includes('【Xuất Thân】')) counts.background++;
    });

    document.querySelectorAll('.wb-filter-btn').forEach(btn => {
        const filterType = btn.dataset.filter;
        let label = '';
        switch(filterType) {
            case 'all': label = 'Tất cả'; break;
            case 'general': label = 'Thế Giới'; break;
            case 'preset': label = 'Khởi Đầu Mẫu'; break;
            case 'talent': label = 'Thiên Phú'; break;
            case 'background': label = 'Xuất Thân'; break;
        }
        if (counts[filterType] !== undefined) {
            btn.innerHTML = `${label} (${counts[filterType]})`;
        }
    });

    container.innerHTML = '';

    const searchInput = document.getElementById('wb-search-input');
    const searchTerm = searchInput ? searchInput.value.toLowerCase().trim() : '';

    const filterPrefixMap = {
        general: '【Thế Giới】',
        preset: '【Khởi Đầu Mẫu】',
        talent: '【Thiên Phú】',
        background: '【Xuất Thân】'
    };

    let filteredEntries = editorData.worldbookEntries;

// Bước 1: Lọc theo danh mục
    if (currentWbFilter !== 'all') {
        const prefix = filterPrefixMap[currentWbFilter];
        if (prefix) {
            // FIX: Sử dụng includes thay vì startsWith và trim tên để tránh lỗi khoảng trắng
            // Hoặc sử dụng Regex để bắt chính xác định dạng 【Thế Giới】 ngay đầu dòng
            filteredEntries = filteredEntries.filter(entry => {
                const name = entry.name.trim();
                return name.startsWith(prefix) || name.includes(prefix); 
            });
        }
    }

    // Bước 2: Lọc theo từ khóa tìm kiếm
    if (searchTerm) {
        filteredEntries = filteredEntries.filter(entry => {
            const nameMatch = entry.name.toLowerCase().includes(searchTerm);
            const contentMatch = entry.content.toLowerCase().includes(searchTerm);
            return nameMatch || contentMatch;
        });
    }

    if (filteredEntries.length === 0 && !editorData.isLoading) {
        let placeholderText = 'Tạm thời không có dữ liệu Sách Thế Giới';
        if (searchTerm) {
            placeholderText = `Không tìm thấy mục khớp với "${searchTerm}"`;
        } else if (currentWbFilter !== 'all') {
            placeholderText = `Không tìm thấy mục khớp với tiền tố "${filterPrefixMap[currentWbFilter] || ''}"`;
        }
        container.innerHTML = `<div class="loading-placeholder">${placeholderText}</div>`;
        return;
    }

    const positionMap = {
        'before_character_definition': 'Trước định nghĩa nhân vật',
        'after_character_definition': 'Sau định nghĩa nhân vật',
        'before_example_messages': 'Trước tin nhắn mẫu',
        'after_example_messages': 'Sau tin nhắn mẫu',
        'before_author_note': 'Trước ghi chú tác giả',
        'after_author_note': 'Sau ghi chú tác giả',
        'at_depth': 'Tại độ sâu chỉ định'
    };

    filteredEntries.forEach(entry => {
        const item = document.createElement('div');
        item.classList.add('editor-item');
        item.dataset.uid = entry.uid;
        const statusClass = entry.enabled ? 'enabled' : 'disabled';
        const strategyClass = entry.strategy?.type || 'constant';
        const positionText = positionMap[entry.position?.type] || 'Vị trí không xác định';

        item.innerHTML = `
            <div class="wb-item-header">
                <div class="wb-item-title">
                    <span class="status-indicator ${statusClass}" title="${entry.enabled ? 'Đã kích hoạt' : 'Đã vô hiệu'}"></span>
                    <span>${entry.name}</span>
                </div>
                <div class="wb-item-indicators">
                    <span class="strategy-indicator ${strategyClass}" title="Chiến lược: ${strategyClass === 'constant' ? 'Hằng số' : 'Có chọn lọc'}"></span>
                    <span>${positionText} (Thứ tự: ${entry.position?.order ?? 'N/A'})</span>
                </div>
            </div>
            <p class="item-description">${entry.content || 'Không có nội dung'}</p>
             <div class="item-actions">
                <button class="editor-btn toggle-wb-btn">
                    ${entry.enabled ? 'Vô hiệu' : 'Kích hoạt'}
                </button>
                <button class="editor-btn edit-wb-btn">Chỉnh sửa</button>
                <button class="editor-btn btn-danger delete-wb-btn">Xóa</button>
            </div>
        `;
        container.appendChild(item);
    });
}


