          function showBatchImportModal(type) {
            const modal = document.getElementById('batch-import-modal');
            document.getElementById('batch-import-type').value = type;
            document.getElementById('batch-import-title').textContent = `Nhập hàng loạt ${type === 'talent' ? 'Thiên phú' : 'Xuất thân'}`;
            document.getElementById('batch-import-content').value = '';
            modal.style.display = 'flex';
          }

          document.getElementById('batch-import-cancel-btn').addEventListener('click', () => {
            document.getElementById('batch-import-modal').style.display = 'none';
          });

          document.getElementById('batch-import-save-btn').addEventListener('click', handleBatchImport);

          async function handleBatchImport() {
            const type = document.getElementById('batch-import-type').value;
            const content = document.getElementById('batch-import-content').value.trim();
            if (!content) {
              await guiXuAlert('Nội dung nhập không được để trống.', 'Cảnh báo');
              return;
            }

            let items;
            try {
              // 尝试将整个内容解析为JSON数组
              items = JSON.parse(content);
            } catch (e) {
              // 如果失败，尝试处理多行JSON对象
              const lines = content.split('\n').filter(line => line.trim() !== '');
              const jsonString = `[${lines.join(',')}]`;
              try {
                items = JSON.parse(jsonString);
              } catch (jsonError) {
                await guiXuAlert('Phân tích JSON thất bại, vui lòng kiểm tra định dạng. Đảm bảo là mảng JSON hợp lệ hoặc mỗi dòng là một đối tượng JSON.', 'Lỗi');
                console.error('JSON Parsing Error:', jsonError);
                return;
              }
            }

            if (!Array.isArray(items)) {
              await guiXuAlert('Dữ liệu nhập phải là một mảng JSON.', 'Lỗi');
              return;
            }

            let successCount = 0;
            let failCount = 0;
            document.getElementById('loading-overlay').style.display = 'flex';

            for (const item of items) {
              try {
                if (await WorldBookManager.saveTalentOrBackground(item, type)) {
                  successCount++;
                } else {
                  failCount++;
                }
              } catch (error) {
                failCount++;
                console.error(`Nhập thất bại: ${item.name}`, error);
              }
            }

            document.getElementById('loading-overlay').style.display = 'none';
            document.getElementById('batch-import-modal').style.display = 'none';

            await guiXuAlert(`Hoàn tất nhập hàng loạt. Thành công: ${successCount}, Thất bại: ${failCount}.`);
            await loadEditorData();
          }

        async function importCustomTextData(text) {
            console.log('JSON parsing failed, attempting custom text import.');
            document.getElementById('loading-overlay').style.display = 'flex';
            let successCount = { talent: 0, background: 0, preset: 0 };
            let errorCount = 0;
            const entries = text.split(/^\s*#\s*comment:/gm).filter(s => s.trim() !== '');
            if (entries.length === 0) {
                document.getElementById('loading-overlay').style.display = 'none';
                throw new Error('Không tìm thấy mục hợp lệ được phân tách bởi "# comment:".');
            }
            for (const entryText of entries) {
                try {
                    const lines = entryText.trim().split('\n');
                    const commentLine = lines.shift().trim();
                    const content = lines.join('\n');
                    const comment = commentLine.replace(/\"/g, '');
                    const titleInfo = WorldBookManager.parseCommentTitle(comment);
                    const yamlData = YAMLParser.parse(content);
                    if (!titleInfo.type || !titleInfo.name) {
                        console.warn('Skipping entry with invalid comment:', comment);
                        errorCount++;
                        continue;
                    }
                    let dataToSave = {}, saveFunction, typeKey;
                    switch (titleInfo.type) {
                        case 'Thiên phú':
                            dataToSave = { name: titleInfo.name, author: titleInfo.author, series: titleInfo.series || yamlData.Hệ_liệt || '', quality: yamlData.Phẩm_giai || '', cost: parseInt(yamlData['Tiêu_hao_điểm_số']) || 0, description: yamlData['Mô_tả'] || '' };
                            saveFunction = (data) => WorldBookManager.saveTalentOrBackground(data, 'talent'); typeKey = 'talent'; break;
                        case 'Xuất thân':
                            dataToSave = { name: titleInfo.name, author: titleInfo.author, series: titleInfo.series || yamlData.Hệ_liệt || '', quality: yamlData.Phẩm_giai || '', description: yamlData['Mô_tả'] || '', initialResources: yamlData['Tài_nguyên_khởi_đầu'] || [] };
                            saveFunction = (data) => WorldBookManager.saveTalentOrBackground(data, 'background'); typeKey = 'background'; break;
                        case 'Khởi Đầu Mẫu':
                            dataToSave = { name: titleInfo.name, author: titleInfo.author, series: titleInfo.series || yamlData.Hệ_liệt || '', points: parseInt(yamlData['Điểm_số']) || 40, description: yamlData['Mô_tả'] || '', attributes: yamlData['Phân_bổ_thuộc_tính'] || {}, requiredTalents: yamlData['Thiên_phú_bắt_buộc'] || [], optionalTalents: yamlData['Thiên_phú_tùy_chọn'] || [] };
                            saveFunction = WorldBookManager.savePreset; typeKey = 'preset'; break;
                        default: console.warn('Unknown entry type:', titleInfo.type); errorCount++; continue;
                    }
                    if (await saveFunction(dataToSave, dataToSave.name)) successCount[typeKey]++;
                    else errorCount++;
                } catch (e) {
                    console.error('Error parsing custom text entry:', e, entryText);
                    errorCount++;
                }
            }
            await loadEditorData();
            document.getElementById('loading-overlay').style.display = 'none';
            await guiXuAlert(`Hoàn tất nhập văn bản tùy chỉnh.\n\nNhập thành công:\n- Thiên phú: ${successCount.talent} cái\n- Xuất thân: ${successCount.background} cái\n- Khởi Đầu Mẫu: ${successCount.preset} cái\n\nThất bại: ${errorCount} cái\n(Xem chi tiết trong console)`);
        }

        async function exportSeriesPackage(preset) {
            if (!preset) return await guiXuAlert('Không có Khởi Đầu Mẫu nào được chọn.');
            const author = (preset.author || '').trim();
            const series = (preset.series || '').trim();
            if (!author || !series) return await guiXuAlert('Không thể xuất gói Hệ liệt: Các trường "Tác giả" và "Hệ liệt" của Khởi Đầu Mẫu phải được điền đầy đủ.');

            document.getElementById('loading-overlay').style.display = 'flex';
            try {
                const allEntries = await TavernHelper.getWorldbook(WorldBookManager.LOREBOOK_NAME);
                const authorTag = `【${author}】`;
                const seriesTag = `【${series}】`;
                const seriesEntries = allEntries.filter(entry => entry.name.includes(authorTag) && entry.name.includes(seriesTag));

                if (seriesEntries.length === 0) {
                    await guiXuAlert(`Không tìm thấy bất kỳ mục Sách Thế Giới nào chứa cả “${authorTag}” và “${seriesTag}”, không thể xuất gói Hệ liệt.`);
                    return;
                }
                const seriesPackage = { type: 'GuixuSeriesPackage', version: '2.5', author, series, exportTime: new Date().toISOString(), entries: seriesEntries };
                exportData(JSON.stringify(seriesPackage, null, 2), `Goi_He_Liet_Quy_Khu_${author}_${series}.json`);
                await guiXuAlert(`Xuất thành công gói Hệ liệt “${series}” (Tác giả: ${author}), bao gồm tổng cộng ${seriesEntries.length} mục!`);
            } catch (error) {
                console.error('Xuất gói Hệ liệt thất bại:', error);
                await guiXuAlert('Xuất gói Hệ liệt thất bại: ' + error.message, 'Lỗi');
            } finally {
                document.getElementById('loading-overlay').style.display = 'none';
            }
        }

        async function importSeriesPackage(packageData) {
            if (!packageData || packageData.type !== 'GuixuSeriesPackage') throw new Error('Tệp không phải là định dạng Gói Hệ liệt Quy Khư hợp lệ.');
            const entryCount = packageData.entries?.length || 0;
            if (entryCount === 0) return await guiXuAlert('Gói Hệ liệt này không chứa bất kỳ mục nào, không cần nhập.');
            if (!(await guiXuConfirm(`Sắp nhập gói Hệ liệt “${packageData.series}” (Tác giả: ${packageData.author}), tổng cộng ${entryCount} mục. Thao tác này sẽ ghi đè các mục cùng tên trong Sách Thế Giới. Bạn có muốn tiếp tục không?`))) return;

            document.getElementById('loading-overlay').style.display = 'flex';
            try {
                const bookName = WorldBookManager.LOREBOOK_NAME;
                let createdCount = 0;
                let updatedCount = 0;

                await TavernHelper.updateWorldbookWith(bookName, (worldbook) => {
                    const existingComments = new Map(worldbook.map(e => [e.name, e]));
                    for (const entry of packageData.entries) {
                        const { uid, ...newEntryData } = entry;
                        if (existingComments.has(entry.name)) {
                            const existing = existingComments.get(entry.name);
                            Object.assign(existing, newEntryData);
                            updatedCount++;
                        } else {
                            worldbook.push(newEntryData);
                            createdCount++;
                        }
                    }
                    return worldbook;
                });

                await loadEditorData();
                await guiXuAlert(`Nhập gói Hệ liệt “${packageData.series}” thành công!\nĐã tạo ${createdCount} mục mới, cập nhật ${updatedCount} mục hiện có.`);
            }  catch (error) {
                 console.error('Lỗi khi nhập gói Hệ liệt:', error);
                 await guiXuAlert('Nhập gói Hệ liệt thất bại: ' + error.message, 'Lỗi');
            } finally {
                 document.getElementById('loading-overlay').style.display = 'none';
            }
        }

        async function handleImportFile(fileContent) {
            try {
                const importedData = JSON.parse(fileContent);
                if (importedData.type === 'GuixuSeriesPackage') {
                    await importSeriesPackage(importedData);
                } else if (importedData.talents || importedData.backgrounds || importedData.presets) {
                    if (await guiXuConfirm("Đây là tệp cấu hình phiên bản cũ, việc nhập sẽ ghi đè tất cả Thiên phú, Xuất thân và Khởi Đầu Mẫu cùng tên. Bạn có muốn tiếp tục không?")) {
                        document.getElementById('loading-overlay').style.display = 'flex';
                        for (const talent of importedData.talents || []) await WorldBookManager.saveTalentOrBackground(talent, 'talent');
                        for (const bg of importedData.backgrounds || []) await WorldBookManager.saveTalentOrBackground(bg, 'background');
                        for (const preset of importedData.presets || []) await WorldBookManager.savePreset(preset);
                        await loadEditorData();
                        await guiXuAlert("Nhập cấu hình đầy đủ thành công!");
                    }
                } else {
                    if (await guiXuConfirm("Tệp trông giống như một Khởi Đầu Mẫu đơn lẻ phiên bản cũ, bạn có muốn nhập nó không?")) {
                        document.getElementById('loading-overlay').style.display = 'flex';
                        await WorldBookManager.savePreset(importedData);
                        await loadEditorData();
                        await guiXuAlert("Nhập Khởi Đầu Mẫu đơn lẻ thành công!");
                    }
                }
            } catch (jsonError) {
                try {
                    await importCustomTextData(fileContent);
                } catch (customError) {
                    await guiXuAlert(`Nhập thất bại: Tệp không phải là định dạng JSON hợp lệ, cũng không phải là định dạng văn bản tùy chỉnh có thể nhận dạng.\n\nLỗi JSON: ${jsonError.message}\nLỗi văn bản tùy chỉnh: ${customError.message}`, 'Nhập thất bại');
                }
            } finally {
                document.getElementById('loading-overlay').style.display = 'none';
            }
        }

        function setupGlobalControls() {
            const importFileInput = document.getElementById('import-file-input');
            document.getElementById('import-all-btn').addEventListener('click', () => importFileInput.click());
            document.getElementById('import-preset-btn').addEventListener('click', () => importFileInput.click());
            importFileInput.addEventListener('change', event => {
                const file = event.target.files[0];
                if (!file) return;
                const reader = new FileReader();
                reader.onload = e => handleImportFile(e.target.result);
                reader.readAsText(file);
                importFileInput.value = '';
            });
            document.getElementById('export-all-btn').addEventListener('click', async () => {
                const dataToExport = { talents: editorData.talents, backgrounds: editorData.backgrounds, presets: editorData.presets };
                exportData(JSON.stringify(dataToExport, null, 2), 'guixu_full_config_backup.json');
                await guiXuAlert('Xuất toàn bộ cấu hình thành công! Đây là bản sao lưu cục bộ đơn giản, để chia sẻ vui lòng sử dụng Gói Hệ liệt.');
            });
            document.getElementById('reset-editor-btn').addEventListener('click', resetEditorToDefaults);
