    // --- START OF SAVE/LOAD MANAGER LOGIC ---
    function _getDisplayText(aiResponse) {
        try {
            if (!aiResponse || typeof aiResponse !== 'string') return '';
            const gameTextMatch = /<gametxt>([\s\S]*?)<\/gametxt>/i.exec(aiResponse);
            if (gameTextMatch && gameTextMatch[1]) {
                const commentRegex = new RegExp('', 'g');
                return gameTextMatch[1].replace(commentRegex, '').trim();
            }
            // Updated regex to use Vietnamese variable names based on [InitVar]
            return aiResponse.replace(/<\/?(Hành Trình Kiếp Này|Gợn Sóng Tiền Kiếp|UpdateVariable|Trích Xuất Nhân Vật|thinking|gametxt|Thiết lập Khởi đầu|Tùy chọn Hành động|action)[\s\S]*?>/gi, '').trim();
        } catch (e) {
            console.error("Lỗi khi phân tích văn bản hiển thị:", e);
            return "[Phân tích tóm tắt thất bại]";
        }
    }

    function getSavesFromStorage() {
        try {
            const saves = localStorage.getItem('guixu_multi_save_data');
            return saves ? JSON.parse(saves) : {};
        } catch (e) {
            console.error("Lấy file lưu thất bại:", e);
            guiXuAlert('Lỗi: File lưu trữ chính đã bị hỏng, không thể đọc.', 'Lỗi');
            return {};
        }
    }

    function showSaveLoadManager() {
        const modal = document.getElementById('save-load-modal');
        const manualContainer = document.getElementById('save-slots-container');
        const autoContainer = document.getElementById('auto-save-slot-container');
        if (!modal || !manualContainer || !autoContainer) return;

        modal.style.display = 'flex';

        let saves;
        try {
            saves = getSavesFromStorage();
        } catch (e) {
            console.error("Phân tích tệp lưu trữ thất bại, có thể do lỗi định dạng JSON:", e);
            manualContainer.innerHTML = `<div style="color: #ff6b6b; padding: 20px; text-align: center;"><p>Lỗi: Tệp lưu trữ chính đã bị hỏng.</p></div>`;
            autoContainer.innerHTML = '';
            return;
        }

        // 1. Render các slot tự động lưu (5 bộ đệm)
        let autoSaveHtml = '';
        const autoSaveSlots = [
            { id: 'auto_save_slot_0', name: 'Bản Tự Động Lưu Mới Nhất', color: '#66CDAA' },
            { id: 'auto_save_slot_1', name: 'Bản Tự Động Lưu-2', color: '#FFD700' },
            { id: 'auto_save_slot_2', name: 'Bản Tự Động Lưu-3', color: '#87CEEB' },
            { id: 'auto_save_slot_3', name: 'Bản Tự Động Lưu-4', color: '#FFA07A' },
            { id: 'auto_save_slot_4', name: 'Bản Tự Động Lưu Lần Trước', color: '#D3D3D3' }
        ];

        autoSaveSlots.forEach(slotInfo => {
            autoSaveHtml += renderSlot(saves[slotInfo.id], slotInfo.id, slotInfo);
        });
        autoContainer.innerHTML = autoSaveHtml;

        // 2. Render các slot lưu thủ công
        let manualHtml = '';
        for (let i = 1; i <= 5; i++) {
            const slotId = `slot_${i}`;
            manualHtml += renderSlot(saves[slotId], slotId, false);
        }
        manualContainer.innerHTML = manualHtml;
    }

    function renderSlot(saveData, slotId, slotInfo) {
        const isAutoSave = typeof slotInfo === 'object';
        const actionsHtml = `
            <div class="save-slot-actions">
                <button class="theme-btn theme-btn-gold btn-small" data-action="load-slot" ${!saveData ? 'disabled' : ''}>Tải File</button>
                <button class="theme-btn theme-btn-gold btn-small" data-action="export-slot" ${!saveData ? 'disabled' : ''}>Xuất File</button>
                <button class="theme-btn theme-btn-red btn-small" data-action="delete-slot" ${!saveData ? 'disabled' : ''}>Xóa</button>
            </div>`;

        let contentHtml;
        const statData = saveData?.mvu_data?.stat_data || saveData?.mvu_data;
        let defaultName = isAutoSave ? slotInfo.name : `File Lưu ${slotId.split('_')[1]}`;
        const slotColor = isAutoSave ? slotInfo.color : '#e0dcd1';

        if (statData) {
            const saveName = saveData.save_name || defaultName;
            const date = new Date(saveData.timestamp).toLocaleString('vi-VN');
            const jingjie = statData['Cảnh giới hiện tại'] || statData['当前境界'] || 'Chưa biết';
            const jinian = statData['Kỷ niên thời gian hiện tại'] || statData['当前时间纪年'] || 'Chưa biết';
            const summary = _getDisplayText(saveData.message_content);
            contentHtml = `
                <div class="slot-name" style="color: ${slotColor};">${saveName}</div>
                ${actionsHtml}
                <div class="slot-time">${date} - ${jingjie} - ${jinian}</div>
                <div class="slot-summary">${summary ? summary.substring(0, 40) + '...' : 'Không có ghi chép chính văn'}</div>`;
        } else {
            contentHtml = `
                <div class="slot-name" style="color: ${slotColor};">${defaultName}</div>
                ${actionsHtml}
                <div class="slot-time" style="font-style: italic; color: #8b7355;">Ô Lưu Trống</div>`;
        }
        return `<div class="save-slot" data-slot-id="${slotId}"><div class="save-slot-info">${contentHtml}</div></div>`;
    }

    async function loadGame(slotId) {
        const allSaves = getSavesFromStorage();
        const saveData = allSaves[slotId];
        if (!saveData) return;

        const saveName = saveData.save_name || slotId;
        if (!(await guiXuConfirm(`Bạn có chắc muốn đọc bản lưu "${saveName}" không? Tiến trình hiện tại chưa lưu sẽ bị ghi đè.`))) return;

        const loadingOverlay = document.getElementById('loading-overlay');
        loadingOverlay.innerHTML = `<p>Đang đọc ký ức của "${saveName}"...</p>`;
        loadingOverlay.style.display = 'flex';

        try {
            const messages = await getChatMessages(0);
            if (!messages || !messages.length === 0) throw new Error("Không thể lấy tin nhắn tầng thứ 0, không thể đọc bản lưu.");

            const messageZero = messages[0];
            messageZero.data = saveData.mvu_data;
            messageZero.message = saveData.message_content || '';

            // --- Mới: Khôi phục từ Sách Thế Giới độc lập đến số thứ tự hiện tại ---
            if (saveData.lorebook_entries) {
                const entries = saveData.lorebook_entries;
                const bookName = WorldBookManager.LOREBOOK_NAME;
                const unifiedIndexInput = document.getElementById('unified-index-input');
                const currentIndex = unifiedIndexInput ? parseInt(unifiedIndexInput.value, 10) : 1;

                const currentJourneyKey = currentIndex > 1 ? `Hành Trình Kiếp Này(${currentIndex})` : 'Hành Trình Kiếp Này';
                const currentPastLivesKey = currentIndex > 1 ? `Gợn Sóng Tiền Kiếp(${currentIndex})` : 'Gợn Sóng Tiền Kiếp';
                const currentNovelModeKey = currentIndex > 1 ? `Chế Độ Tiểu Thuyết(${currentIndex})` : 'Chế Độ Tiểu Thuyết'; // Simplified handling

                await TavernHelper.updateWorldbookWith(bookName, async (allEntries) => {
                    const findOrCreate = (targetKey, sourceKey, baseKey, order) => {
                        const sourceEntry = allEntries.find(e => e.name === entries[sourceKey]);
                        const targetEntry = allEntries.find(e => e.name === targetKey);
                        if (sourceEntry) {
                            if (targetEntry) {
                                targetEntry.content = sourceEntry.content || '';
                            } else {
                                const base = allEntries.find(e => e.name === baseKey) || {};
                                allEntries.push({ ...base, uid: undefined, name: targetKey, content: sourceEntry.content || '', strategy: { ...base.strategy, keys: [...(base.strategy?.keys || []), targetKey] }, enabled: true, position: { ...base.position, order } });
                            }
                        }
                    };
                    findOrCreate(currentJourneyKey, 'journey_entry_name', 'Hành Trình Kiếp Này', 20);
                    findOrCreate(currentPastLivesKey, 'past_lives_entry_name', 'Gợn Sóng Tiền Kiếp', 19);
                    findOrCreate(currentNovelModeKey, 'novel_mode_entry_name', 'Chế Độ Tiểu Thuyết', 18);

                    return allEntries;
                });
                console.log(`[Đọc bản lưu Quy Khư] Đã ghi đè dữ liệu Sách Thế Giới của bản lưu "${saveName}" vào số thứ tự hiện tại ${currentIndex}`);
            }

            await TavernHelper.setChatMessages([messageZero], { refresh: 'all' });
            await guiXuAlert('Đọc bản lưu thành công! Trang sẽ được làm mới để áp dụng các thay đổi.');
            window.location.reload();

        } catch (error) {
            console.error('Đọc bản lưu thất bại:', error);
            await guiXuAlert(`Đọc bản lưu thất bại: ${error.message}`, 'Lỗi');
        } finally {
            loadingOverlay.style.display = 'none';
        }
    }

    async function deleteSave(slotId) {
        const allSaves = getSavesFromStorage();
        const saveDataToDelete = allSaves[slotId];
        if (!saveDataToDelete) return;

        const slotName = saveDataToDelete.save_name || `Bản lưu ${slotId.replace(/slot_|auto_save_slot_/, '')}`;
        let confirmMsg = `Bạn có chắc muốn xóa bản lưu "${slotName}" không? Thao tác này không thể khôi phục.`;
        if (saveDataToDelete.lorebook_entries) {
            confirmMsg += `\nCác mục Sách Thế Giới liên quan cũng sẽ bị xóa cùng.`;
        }

        if (await guiXuConfirm(confirmMsg)) {
            try {
                if (saveDataToDelete.lorebook_entries) {
                    const bookName = WorldBookManager.LOREBOOK_NAME;
                    const entryNamesToDelete = Object.values(saveDataToDelete.lorebook_entries);
                    await TavernHelper.updateWorldbookWith(bookName, (worldbook) => {
                        return worldbook.filter(e => !entryNamesToDelete.includes(e.name));
                    });
                }
                delete allSaves[slotId];
                localStorage.setItem('guixu_multi_save_data', JSON.stringify(allSaves));
                await guiXuAlert(`"${slotName}" đã bị xóa.`);
                showSaveLoadManager();
            } catch (error) {
                console.error('Xóa bản lưu thất bại:', error);
                await guiXuAlert(`Xóa bản lưu thất bại: ${error.message}`, 'Lỗi');
            }
        }
    }

    // === Nâng cấp tính năng: Tăng cường chức năng "Xóa Toàn bộ File Đã Lưu" ===
    async function clearAllSaves() {
        const allSaves = getSavesFromStorage();
        const hasLocalStorageSaves = Object.keys(allSaves).length > 0;
        const bookName = WorldBookManager.LOREBOOK_NAME;
        const lorebookCommentsToDelete = new Set();
        let uidsToDelete = [];

        try {
            document.getElementById('loading-overlay').style.display = 'flex';
            const allLorebookEntries = await TavernHelper.getWorldbook(bookName);

            // Regex tăng cường, khớp với nhiều định dạng tàn dư bản lưu
            const snapshotRegex = /^(.*?)[:：-]\s*(Hành Trình Kiếp Này|Gợn Sóng Tiền Kiếp|Chế Độ Tiểu Thuyết)(\(\d+\))?$/i;

            // 1. Quét Sách Thế Giới, tìm các mục tàn dư phù hợp
            allLorebookEntries.forEach(entry => {
                const trimmedName = entry.name ? entry.name.trim() : '';
                if (snapshotRegex.test(trimmedName)) {
                    lorebookCommentsToDelete.add(trimmedName);
                }
            });

            // 2. Kiểm tra liên kết trong file lưu cũ, đảm bảo tính tương thích
            Object.values(allSaves).forEach(save => {
                if (save.lorebook_entries) {
                    Object.values(save.lorebook_entries).forEach(name => {
                        if (name) lorebookCommentsToDelete.add(name);
                    });
                }
            });

            // 3. Lấy danh sách UID cuối cùng dựa trên tên đã thu thập
            uidsToDelete = allLorebookEntries
                .filter(entry => lorebookCommentsToDelete.has(entry.name ? entry.name.trim() : ''))
                .map(entry => entry.uid);

            const hasLorebookSnapshots = uidsToDelete.length > 0;
            if (!hasLocalStorageSaves && !hasLorebookSnapshots) {
                await guiXuAlert("Không có dữ liệu lưu trữ để xóa.");
                return;
            }

            let confirmMsg = `Bạn có chắc chắn muốn xóa toàn bộ bản lưu không? Thao tác này không thể khôi phục.\n\n`;
            confirmMsg += hasLocalStorageSaves ? `> Sẽ xóa ${Object.keys(allSaves).length} ô lưu cục bộ.\n` : `> Không tìm thấy ô lưu cục bộ.\n`;

            if (hasLorebookSnapshots) {
                const namesToList = Array.from(lorebookCommentsToDelete).sort().join('\n- ');
                confirmMsg += `> Sẽ xóa ${uidsToDelete.length} mục bản lưu nhanh liên quan từ Sách Thế Giới 【${bookName}】:\n- ${namesToList}`;
            } else {
                confirmMsg += `> Không tìm thấy bản lưu nhanh cần xóa trong Sách Thế Giới.`;
            }

            if (!(await guiXuConfirm(confirmMsg, "Xác nhận thao tác nguy hiểm"))) return;

            // 4. Thực hiện xóa
            if (hasLorebookSnapshots) {
                await TavernHelper.updateWorldbookWith(bookName, (worldbook) => {
                    return worldbook.filter(entry => !uidsToDelete.includes(entry.uid));
                });
            }
            if (hasLocalStorageSaves) {
                localStorage.removeItem('guixu_multi_save_data');
            }

            await guiXuAlert(`Đã xóa toàn bộ bản lưu và các bản lưu nhanh Sách Thế Giới liên quan.`);
            showSaveLoadManager(); // Refresh the save list UI

        } catch (error) {
            console.error('Lỗi khi xóa toàn bộ bản lưu:', error);
            await guiXuAlert(`Xóa bản lưu thất bại: ${error.message}`, 'Lỗi');
        } finally {
            document.getElementById('loading-overlay').style.display = 'none';
        }
    }

    async function exportSave(slotId) {
        const allSaves = getSavesFromStorage();
        const saveData = allSaves[slotId];
        if (!saveData) return;

        try {
            const dataToExport = {
                exportVersion: '1.0',
                exportedAt: new Date().toISOString(),
                saveData: saveData,
                lorebookData: []
            };

            if (saveData.lorebook_entries) {
                const bookName = WorldBookManager.LOREBOOK_NAME;
                const entryNames = Object.values(saveData.lorebook_entries);
                const allEntries = await TavernHelper.getWorldbook(bookName);
                dataToExport.lorebookData = allEntries.filter(e => entryNames.includes(e.name));
            }

            const fileName = `${(saveData.save_name || `guixu_save_${slotId}`).replace(/[^a-z0-9]/gi, '_')}.json`;
            exportData(JSON.stringify(dataToExport, null, 2), fileName);
            await guiXuAlert('Đã xuất bản lưu thành công!');
        } catch (error) {
            console.error('Xuất bản lưu thất bại:', error);
            await guiXuAlert(`Xuất thất bại: ${error.message}`, 'Lỗi');
        }
    }

    async function handleFileImport(event) {
        const file = event.target.files[0];
        if (!file) return;
        const reader = new FileReader();
        reader.onload = async (e) => {
            try {
                const importedData = JSON.parse(e.target.result);
                let saveDataToImport;
                let lorebookDataToImport = [];

                if (importedData.exportVersion === '1.0') { // New format
                    saveDataToImport = importedData.saveData;
                    lorebookDataToImport = importedData.lorebookData || [];
                } else { // Old format
                    saveDataToImport = importedData;
                }

                if (!saveDataToImport || !saveDataToImport.timestamp || !saveDataToImport.mvu_data) {
                    throw new Error('Định dạng tệp bản lưu không hợp lệ.');
                }

                const slotId = await promptForSlotSelection(saveDataToImport.save_name || 'Bản lưu được nhập');
                if (!slotId) return;

                const allSaves = getSavesFromStorage();
                const bookName = WorldBookManager.LOREBOOK_NAME;

                // Handle lorebook entries
                if (lorebookDataToImport.length > 0) {
                    await TavernHelper.updateWorldbookWith(bookName, (worldbook) => {
                        const existingNames = new Set(worldbook.map(e => e.name));
                        lorebookDataToImport.forEach(entry => {
                            if (!existingNames.has(entry.name)) {
                                const { uid, ...newEntry } = entry;
                                worldbook.push(newEntry);
                            }
                        });
                        return worldbook;
                    });
                }

                allSaves[slotId] = saveDataToImport;
                localStorage.setItem('guixu_multi_save_data', JSON.stringify(allSaves));
                await guiXuAlert(`Bản lưu đã được nhập thành công vào ${slotId.replace('slot_', 'Vị trí lưu ')}.`);
                showSaveLoadManager();

            } catch (error) {
                await guiXuAlert(`Nhập thất bại: ${error.message}`, 'Lỗi');
            }
        };
        reader.readAsText(file);
        event.target.value = '';
    }

    function promptForSlotSelection(importName) {
        return new Promise(resolve => {
            const modal = document.createElement('div');
            modal.className = 'modal-overlay';
            modal.style.cssText = 'display: flex; z-index: 2001;';
            let slotsHtml = '';
            for (let i = 1; i <= 5; i++) slotsHtml += `<button class="theme-btn theme-btn-gold" data-slot-id="slot_${i}">Vị trí lưu ${i}</button>`;
            modal.innerHTML = `
              <div class="modal-content" style="width: 450px; height: auto;">
                <h2 class="modal-title">Chọn vị trí nhập</h2>
                <div class="modal-body" style="padding: 20px;">
                  <p>Vui lòng chọn một vị trí lưu để nhập "${importName}":</p>
                  <div style="display: flex; justify-content: center; gap: 10px; flex-wrap: wrap; margin-top:20px;">${slotsHtml}</div>
                  <div class="modal-actions"><button class="theme-btn theme-btn-red" id="import-cancel-btn">Hủy bỏ</button></div>
                </div>
              </div>`;
            document.body.appendChild(modal);
            modal.addEventListener('click', (e) => {
                const target = e.target;
                if (target.dataset.slotId) {
                    resolve(target.dataset.slotId);
                    modal.remove();
                } else if (target.id === 'import-cancel-btn' || target === modal) {
                    resolve(null);
                    modal.remove();
                }
            });
        });
    }

    function setupSaveManagerEventListeners() {
        document.getElementById('show-save-manager-btn').addEventListener('click', showSaveLoadManager);
        const modal = document.getElementById('save-load-modal');
        if (!modal) return;
        modal.addEventListener('click', (e) => {
            const button = e.target.closest('[data-action]');
            if (e.target.matches('.modal-overlay')) modal.style.display = 'none';
            if (!button) return;
            const action = button.dataset.action;
            const slotId = button.closest('.save-slot')?.dataset.slotId;
            switch (action) {
                case 'close-modal': modal.style.display = 'none'; break;
                case 'load-slot': if (slotId) loadGame(slotId); break;
                case 'export-slot': if (slotId) exportSave(slotId); break;
                case 'delete-slot': if (slotId) deleteSave(slotId); break;
                case 'import-save': document.getElementById('import-save-file-input').click(); break;
                case 'clear-all-saves': clearAllSaves(); break;
            }
        });
        document.getElementById('import-save-file-input').addEventListener('change', handleFileImport);
    }
    // --- END OF SAVE/LOAD MANAGER LOGIC ---

    // --- START OF SNAPSHOT CLEANUP MANAGER ---
    async function showSnapshotManager() {
        const modal = document.getElementById('snapshot-manager-modal');
        const loadingOverlay = document.getElementById('loading-overlay');
        loadingOverlay.style.display = 'flex';

        try {
            const allEntries = await TavernHelper.getWorldbook(WorldBookManager.LOREBOOK_NAME);

            // Định nghĩa regex cho bản lưu nhanh (Snapshots)
            const gameProcessRegex = /^(Hành Trình Kiếp Này|Gợn Sóng Tiền Kiếp)(\(\d+\))?$/;
            const nonGameProcessRegex = /^(.+[:-]\s*)?Chế Độ Tiểu Thuyết(\(\d+\))?$/;

            const gameProcessSnapshots = [];
            const nonGameProcessSnapshots = [];

            allEntries.forEach(entry => {
                const name = entry.name.trim();
                if (gameProcessRegex.test(name)) {
                    gameProcessSnapshots.push(entry);
                } else if (nonGameProcessRegex.test(name)) {
                    nonGameProcessSnapshots.push(entry);
                }
            });

            const renderList = (snapshots) => {
                if (snapshots.length === 0) return '<div class="loading-placeholder">Không có mục phù hợp</div>';
                return snapshots.map(s => `
                    <label class="snapshot-item">
                        <input type="checkbox" class="snapshot-checkbox" value="${s.uid}">
                        <span class="snapshot-item-name">${s.name}</span>
                        <span class="snapshot-item-uid">UID: ${s.uid}</span>
                    </label>
                `).join('');
            };

            document.getElementById('game-process-snapshot-list').innerHTML = renderList(gameProcessSnapshots);
            document.getElementById('non-game-process-snapshot-list').innerHTML = renderList(nonGameProcessSnapshots);

            modal.style.display = 'flex';

        } catch (error) {
            console.error('Mở trình Dọn Dẹp Bản Lưu Nhanh thất bại:', error);
            await guiXuAlert('Không thể tải danh sách bản lưu nhanh: ' + error.message, 'Lỗi');
        } finally {
            loadingOverlay.style.display = 'none';
        }
    }

    function setupSnapshotManagerEventListeners() {
        const modal = document.getElementById('snapshot-manager-modal');
        if (!modal) return;

        // Nút "Mở"
        document.getElementById('show-snapshot-manager-btn').addEventListener('click', showSnapshotManager);

        const selectionInfo = document.getElementById('snapshot-selection-info');
        const deleteBtn = document.getElementById('delete-selected-snapshots-btn');

        // Cập nhật trạng thái đếm và nút xóa
        const updateSelectionState = () => {
            const checkedBoxes = modal.querySelectorAll('.snapshot-checkbox:checked');
            const count = checkedBoxes.length;
            selectionInfo.textContent = `Đã chọn ${count} mục`;
            deleteBtn.disabled = count === 0;
        };

        // Xử lý sự kiện ủy quyền (Event delegation) cho các click trong modal
        modal.addEventListener('click', async (e) => {
            const target = e.target;

            // Nút đóng
            if (target.closest('.modal-close-btn') || target.matches('.modal-overlay')) {
                modal.style.display = 'none';
                return;
            }

            // Checkbox "Chọn tất cả"
            if (target.matches('input[data-group]')) {
                const group = target.dataset.group;
                const listId = group === 'game-process' ? 'game-process-snapshot-list' : 'non-game-process-snapshot-list';
                const checkboxes = document.getElementById(listId).querySelectorAll('.snapshot-checkbox');
                checkboxes.forEach(box => box.checked = target.checked);
                updateSelectionState();
                return;
            }

            // Checkbox từng mục
            if (target.classList.contains('snapshot-checkbox')) {
                updateSelectionState();
                return;
            }

            // Nút "Xóa"
            if (target.id === 'delete-selected-snapshots-btn') {
                const checkedBoxes = modal.querySelectorAll('.snapshot-checkbox:checked');
                const uidsToDelete = Array.from(checkedBoxes).map(box => box.value);

                if (uidsToDelete.length > 0 && await guiXuConfirm(`Bạn có chắc chắn muốn xóa ${uidsToDelete.length} mục bản lưu nhanh đã chọn không? Thao tác này không thể khôi phục.`, 'Xác nhận xóa')) {
                    const loadingOverlay = document.getElementById('loading-overlay');
                    loadingOverlay.style.display = 'flex';
                    try {
                        await WorldBookManager._saveOrUpdateWith(worldbook => {
                            return worldbook.filter(entry => !uidsToDelete.includes(String(entry.uid)));
                        });
                        await guiXuAlert('Các bản lưu nhanh đã chọn đã được xóa thành công.');
                        modal.style.display = 'none';
                    } catch (error) {
                        console.error('Xóa bản lưu nhanh thất bại:', error);
                        await guiXuAlert('Xóa thất bại: ' + error.message, 'Lỗi');
                    } finally {
                        loadingOverlay.style.display = 'none';
                    }
                }
            }
        });
    }

