    function writePromptAndCloseUI(finalPrompt) {
        let targetWindow = window;
        let targetDoc = document;
        let sendTextarea = document.getElementById('send_textarea');

        if (!sendTextarea && window.parent && window.parent !== window) {
            try {
                targetWindow = window.parent;
                targetDoc = window.parent.document;
                sendTextarea = targetDoc.getElementById('send_textarea');
            } catch (e) {
                console.warn("Không thể truy cập window.parent:", e);
            }
        }

        if (sendTextarea) {
            if (typeof targetWindow.insertTextIntoMessage === 'function') {
                targetWindow.insertTextIntoMessage(finalPrompt);
            } else {
                // Gọi cách cồng kềnh với React / jQuery nếu thiếu ST core function
                sendTextarea.value = finalPrompt;
                if (typeof targetWindow.$ !== 'undefined') targetWindow.$('#send_textarea').val(finalPrompt).trigger('input');
                let nativeInputValueSetter = Object.getOwnPropertyDescriptor(targetWindow.HTMLTextAreaElement.prototype, "value").set;
                if (nativeInputValueSetter) nativeInputValueSetter.call(sendTextarea, finalPrompt);
                sendTextarea.dispatchEvent(new Event('input', { bubbles: true }));
                sendTextarea.dispatchEvent(new Event('change', { bubbles: true }));
            }
        } else {
            console.warn("Không tìm thấy ô nhập liệu (send_textarea) kể cả trong parent document.");
        }

        if (window.parent && window.parent !== window) {
            try {
                // Xóa tin nhắn Khai mạc bằng mọi cách có thể (Slash Command + API + DOM)
                try {
                    // 1. Phá hủy DOM trực tiếp để mắt người dùng không còn thấy tin nhắn này nữa (Bạo lực)
                    if (typeof targetWindow.$ !== 'undefined') {
                        const firstMsg = targetWindow.$('.mes[mesid="0"]');
                        if (firstMsg.text().includes('<Khai mạc>')) {
                            firstMsg.hide(); // Ẩn ngay lập tức
                        }
                    }

                    // 2. Dùng Slash Commands
                    const commands = [
                        '/delchat 0-0', // Default ST command
                        '/quicksweep 0', // Some branches support quick sweep
                        '/sys delchat 0', // Sys extension
                        '/sys editswipe 0 0 ' // Replace with empty string
                    ];

                    if (typeof targetWindow.executeSlashCommands === 'function') {
                        commands.forEach(cmd => targetWindow.executeSlashCommands(cmd));
                    } else if (typeof targetWindow.SlashCommandParser !== 'undefined') {
                        commands.forEach(cmd => targetWindow.SlashCommandParser.execute(cmd));
                    }

                    // 3. Xóa qua API Context (bất đồng bộ)
                    const pWindow = window.parent;
                    if (pWindow && pWindow.chat && Array.isArray(pWindow.chat)) {
                        if (pWindow.chat[0] && pWindow.chat[0].mes === '<Khai mạc>\n</Khai mạc>') {
                            pWindow.chat.shift(); // Hard delete từ mảng bộ nhớ
                            if (typeof pWindow.saveChatDebounced === 'function') pWindow.saveChatDebounced();
                            if (typeof pWindow.printMessages === 'function') pWindow.printMessages();
                        }
                    }
                } catch(err) {
                    console.warn("Lỗi khi auto xóa tin nhắn Khai mạc:", err);
                }

                if (typeof targetWindow.executeSlashCommands === 'function') {
                    targetWindow.executeSlashCommands('/sys delcui 0');
                } else if (typeof targetWindow.SlashCommandParser !== 'undefined' && targetWindow.SlashCommandParser.commands && targetWindow.SlashCommandParser.commands['sys']) {
                    targetWindow.SlashCommandParser.commands['sys'].callback({}, 'delcui 0');
                }

                // Thu hồi UI trực tiếp từ DOM nếu lệnh sys delcui 0 không hoạt động
                const iframes = window.parent.document.querySelectorAll('iframe');
                for (let i = 0; i < iframes.length; i++) {
                    if (iframes[i].contentWindow === window) {
                        const iframe = iframes[i];
                        const popup = iframe.closest('.popup, .dialog-box, .drawer-content, .generic-popup, .custom-modal-overlay, .modal-overlay, #custom-modal-overlay');
                        if (popup) popup.remove();
                        iframe.remove();
                        break;
                    }
                }
            } catch (e) {
                console.warn("Lỗi khi đóng popup parent:", e);
            }
        }
    }

    async function startWithQuickStart(templateName) {
      const templates = getQuickStartTemplates();
      const prompt = templates[templateName];
      if (!prompt) {
        guiXuAlert('Không tìm thấy mẫu này.');
        return;
      }

      if (!(await guiXuConfirm(`Bạn có chắc muốn sử dụng mẫu "${templateName}" để bắt đầu trò chơi không?`))) return;

      writePromptAndCloseUI(prompt);
    }

    function deleteQuickStartTemplate(templateName) {
        const templates = getQuickStartTemplates();
        delete templates[templateName];
        localStorage.setItem(QUICK_START_KEY, JSON.stringify(templates));
        renderQuickStartList();
    }

    document.addEventListener('DOMContentLoaded', () => {
      // Main UI Listeners
      document.getElementById('show-editor-btn').addEventListener('click', async () => {
          currentEditingPreset = null;
          await showView('editor-container');
      });
      document.getElementById('quick-start-btn').addEventListener('click', () => {
        renderQuickStartList();
        showView('quick-start-container');
      });

      // --- Quick Start Event Handlers ---
      async function createNewQuickStartTemplateInScope() {
        const name = await guiXuPrompt("Vui lòng nhập tên mẫu mới:");
        if (!name) return;
        const templates = getQuickStartTemplates();
        if (templates[name]) {
          return guiXuAlert(`Mẫu "${name}" đã tồn tại.`);
        }
        const result = await guiXuPromptEditable("Vui lòng nhập nội dung mẫu:", '', 'Tạo Mẫu Mới', 'template');
        if (result && result.button === 'save' && result.value) {
          saveQuickStartTemplate(name, result.value);
          renderQuickStartList();
        }
      }

      async function editQuickStartTemplateInScope(oldName) {
        const templates = getQuickStartTemplates();
        const oldPrompt = templates[oldName];
        if (!oldPrompt) return guiXuAlert('Không tìm thấy mẫu cần chỉnh sửa.');

        const newName = await guiXuPrompt("Vui lòng nhập tên mới cho mẫu:", oldName);
        if (!newName) return;

        if (newName !== oldName && templates[newName]) {
            return guiXuAlert(`Mẫu "${newName}" đã tồn tại.`);
        }

        const result = await guiXuPromptEditable("Vui lòng chỉnh sửa nội dung mẫu:", oldPrompt, 'Chỉnh sửa mẫu', 'template');
        if (result && result.button === 'save' && result.value) {
            delete templates[oldName];
            templates[newName] = result.value;
            localStorage.setItem(QUICK_START_KEY, JSON.stringify(templates));
            guiXuAlert(`Mẫu "${newName}" đã được cập nhật!`);
            renderQuickStartList();
        }
      }

      document.getElementById('quick-start-container').addEventListener('click', async e => {
        const target = e.target;
        if (target.id === 'back-to-main-from-quick-start-btn') {
          return showView('main-page-content');
        }
        if (target.id === 'create-new-template-btn') {
          return createNewQuickStartTemplateInScope();
        }

        const templateItem = target.closest('.choice-item');
        if (!templateItem) return;

        const templateName = templateItem.dataset.templateName;
        const actionBtn = target.closest('[data-action]');

        if (actionBtn) {
            const action = actionBtn.dataset.action;
            if (action === 'delete') {
                if (await guiXuConfirm(`Bạn có chắc muốn xóa mẫu "${templateName}" không?`)) {
                    deleteQuickStartTemplate(templateName);
                }
            } else if (action === 'edit') {
                await editQuickStartTemplateInScope(templateName);
            }
        } else {
            // If the item itself is clicked (but not a button), start the game
            await startWithQuickStart(templateName);
        }
      });
