    // --- Talent Gacha Logic ---
    const talentGachaConfig = {
        pullOneCost: 10,
        pullTenCost: 100,
        baseRate5Star: 0.006,
        baseRate4Star: 0.051,
        softPityStart: 74,
        hardPity5Star: 90,
        hardPity4Star: 10,
        softPityIncreaseRate: 0.06,
        qualities: {
            shen: { star: 5, pool: [] },
            xian: { star: 5, pool: [] },
            tian: { star: 4, pool: [] },
            ji: { star: 4, pool: [] },
            shang: { star: 3, pool: [] },
            zhong: { star: 3, pool: [] },
            xia: { star: 3, pool: [] },
            fan: { star: 3, pool: [] },
        }
    };

    function performTalentPull() {
        gameState.pity5++;
        gameState.pity4++;

        // Initialize pools if they are empty
        const qualityKeyMap = { 'Thần phẩm':'shen', 'Tiên phẩm':'xian', 'Thiên phẩm':'tian', 'Cực phẩm':'ji', 'Thượng phẩm':'shang', 'Trung phẩm':'zhong', 'Hạ phẩm':'xia', 'Phàm phẩm':'fan' };
        if (talentGachaConfig.qualities.shen.pool.length === 0) {
            for (const quality in qualityKeyMap) {
                const key = qualityKeyMap[quality];
                talentGachaConfig.qualities[key].pool = editorData.talents.filter(t => t.quality === quality);
            }
        }

        if (gameState.pity5 >= talentGachaConfig.hardPity5Star) return get5StarTalent();
        if (gameState.pity4 >= talentGachaConfig.hardPity4Star) return get4StarTalent();

        const random = Math.random();
        let current5StarRate = talentGachaConfig.baseRate5Star;
        if (gameState.pity5 >= talentGachaConfig.softPityStart) {
            current5StarRate += (gameState.pity5 - talentGachaConfig.softPityStart + 1) * talentGachaConfig.softPityIncreaseRate;
        }

        if (random < current5StarRate) return get5StarTalent();
        if (random < current5StarRate + talentGachaConfig.baseRate4Star) return get4StarTalent();

        return get3StarTalent();
    }

    function getRandomTalent(pool) {
        if (!pool || pool.length === 0) {
            return { name: 'Trống rỗng', quality: 'Phàm phẩm', description: 'Không có', id: 'empty' };
        }
        return pool[Math.floor(Math.random() * pool.length)];
    }

    function get5StarTalent() {
        gameState.pity5 = 0;
        // 抽中5星不再重置4星保底
        // gameState.pity4 = 0;

        if (gameState.is5StarGuaranteed) {
            gameState.is5StarGuaranteed = false;
            return getRandomTalent(talentGachaConfig.qualities.shen.pool); // Thần phẩm
        }

        if (Math.random() < 0.5) {
            return getRandomTalent(talentGachaConfig.qualities.shen.pool); // Thần phẩm
        } else {
            gameState.is5StarGuaranteed = true;
            // Intentionally fall through to get a 4-star or 3-star talent, since the 5-star was "off-banner"
        }
    }

    function get4StarTalent() {
        gameState.pity4 = 0;
        // 4-star pity doesn't have a guarantee in this implementation, but can be added if needed.
        if (Math.random() < 0.5) {
            return getRandomTalent(talentGachaConfig.qualities.tian.pool); // Thiên phẩm
        } else {
            return getRandomTalent(talentGachaConfig.qualities.ji.pool); // Cực phẩm
        }
    }

    function get3StarTalent() {
        const rand = Math.random();
        if (rand < 0.20) return getRandomTalent(talentGachaConfig.qualities.shang.pool); // Thượng phẩm 20%
        if (rand < 0.40) return getRandomTalent(talentGachaConfig.qualities.zhong.pool); // Trung phẩm 20%
        if (rand < 0.70) return getRandomTalent(talentGachaConfig.qualities.xia.pool);   // Hạ phẩm 30%
        return getRandomTalent(talentGachaConfig.qualities.fan.pool);     // Phàm phẩm 30%
    }

    function displayTalentGachaResults(results) {
