      async function togglePresetWorldbooks(preset) {
          const series = (preset.series || '').trim();
          const author = (preset.author || '').trim();
          if (!series || !author) {
              console.log(`Khởi Đầu Mẫu "${preset.name}" chưa thiết lập Hệ liệt hoặc Tác giả, bỏ qua việc tự động chuyển đổi Sách Thế Giới.`);
              return;
          }

          const targetPrefix = `【Thế Giới】【${series}】【${author}】`;
          console.log(`Đang chuyển đổi Sách Thế Giới cho Khởi Đầu Mẫu "${preset.name}", tiền tố mục tiêu: ${targetPrefix}`);

          try {
              let changed = false;
              await WorldBookManager._saveOrUpdateWith(worldbook => {
                  worldbook.forEach(entry => {
                      if (entry.name.startsWith('【Thế Giới】【') && entry.name.includes('】【')) {
                          if (entry.name.startsWith(targetPrefix)) {
                              if (!entry.enabled) {
                                  entry.enabled = true;
                                  changed = true;
                              }
                          } else {
